# Timeout (seconds) for 3D rendering calls that may hang in headless/offscreen mode
# [M752 F6-6] 15→8s: 3 calls × 15s = 45s worst case → 8s: 3 calls × 8s = 24s max
# MAGIC: 8 = 사용자 체감 한계 30s 이내 보장, cumulative guard 20s 추가 (하단 참조)
_RENDER_TIMEOUT_SEC = 8  # seconds per 3D rendering call

# Headless mode detection: when QT_QPA_PLATFORM=offscreen (patrol/CI tests),
# skip expensive image generation (spectrum PNGs, 3D renders) and produce
# text-only PDF.  This cuts export time from ~60s to <10s.
_HEADLESS_MODE = os.environ.get("QT_QPA_PLATFORM", "").lower() == "offscreen"


def _run_with_timeout(fn, timeout_sec: float = _RENDER_TIMEOUT_SEC,
                      default=None):
    """Run *fn* (no-arg callable) in a thread with timeout.

    Returns *default* if *fn* exceeds *timeout_sec* or raises an exception.
    Uses concurrent.futures.ThreadPoolExecutor for cross-platform safety.

    Rule M: logs a warning instead of silently returning default.
    """
    try:
        with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
            future = executor.submit(fn)
            result = future.result(timeout=timeout_sec)
            return result
    except concurrent.futures.TimeoutError:
        logger.warning(
            "_run_with_timeout: %s exceeded %ss timeout — returning default",
            getattr(fn, '__name__', repr(fn)), timeout_sec,
        )
        return default
    except Exception as e:
        logger.warning(
            "_run_with_timeout: %s raised %s: %s — returning default",
            getattr(fn, '__name__', repr(fn)), type(e).__name__, e,
        )
        return default


def _review_mechanism_with_llm(steps, reaction_name=""):
    """Use local Qwen LLM to review mechanism step descriptions.

    Returns list of (step_index, suggestion) tuples, or empty list if LLM unavailable.
    Non-blocking: returns empty list on any error (timeout, connection refused, etc.)
    """
    try:
        import sys as _sys_llm
        _housing_llm_dir = os.path.join(
            os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))),
            'housing', 'local_llm')
        if _housing_llm_dir not in _sys_llm.path:
            _sys_llm.path.insert(0, _housing_llm_dir)
        from ollama_client import OllamaClient

        client = OllamaClient()
        health = client.health_check()
        if health == []:
            logger.warning("_review_mechanism_with_llm: optional LLM health_check returned []")
            return []
        if not health:
            logger.warning("_review_mechanism_with_llm: optional LLM health_check unavailable: %r", health)
            return []

        # Build prompt from mechanism steps
        step_text = "\n".join(
            f"Step {i+1}: {s.get('annotation', s.get('label', '')) if isinstance(s, dict) else str(s)}"
            for i, s in enumerate(steps)
        )

        prompt = (
            f"Review this organic chemistry mechanism for {reaction_name}.\n"
            "Check for chemical accuracy errors only (wrong intermediates, "
            "missing steps, incorrect arrow pushing logic).\n"
            "Reply with ONLY specific corrections needed, or \"OK\" if correct.\n"
            "Keep response under 100 words.\n\n"
            f"{step_text}"
        )

        result = client.generate(
            model="qwen3.5:9b",
            prompt=prompt,
            system="You are an organic chemistry professor reviewing reaction mechanisms. Be concise.",
            temperature=0.1,
            max_tokens=200,
        )

        if not isinstance(result, dict):
            logger.warning("_review_mechanism_with_llm: LLM result is not dict (type=%s)", type(result).__name__)
            return []
        text = result.get("text", "").strip()
        if not text or text.upper().startswith("OK"):
            return []

        return [(0, text)]  # Single review for the whole mechanism

    except Exception as e:
        logger.warning("_review_mechanism_with_llm failed: %s", e)
        return []  # LLM review is optional; warning above prevents silent failure.


# ── Cached predict_all result ──
_predict_all_cache: Dict[str, Any] = {}


def _get_predicted_spectra(smiles: str):
    """Get predict_all() result with caching. Returns PredictedSpectra or None."""
    if smiles in _predict_all_cache:
        return _predict_all_cache[smiles]
    try:
        from predict_spectra import predict_all as _predict_all
    except ImportError as e:
        logger.debug("Optional module not available (predict_spectra): %s", e)
        try:
            import sys as _sys
            src_dir = os.path.dirname(os.path.abspath(__file__))
            if src_dir not in _sys.path:
                _sys.path.insert(0, src_dir)
            from predict_spectra import predict_all as _predict_all
        except ImportError as e:
            logger.debug("Optional module not available (predict_spectra): %s", e)
            _predict_all_cache[smiles] = None
            return None
    try:
        result = _predict_all(smiles)
        _predict_all_cache[smiles] = result
        return result
    except Exception as e:
        logger.warning("_get_predicted_spectra failed: %s", e)
        _predict_all_cache[smiles] = None
        return None

