class _DictObj:
    """Wrapper to access dict values as attributes.

    Allows uniform getattr() access whether derivative data
    is passed as a dict or a dataclass/namedtuple.
    """

    def __init__(self, d: dict):
        self.__dict__.update(d)

    def __repr__(self):
        return f"_DictObj({self.__dict__})"


@dataclass
class DryLabData:
    """All data needed for DryLab report generation."""
    smiles: str = ""
    name: str = ""
    mol_data: Dict[str, Any] = field(default_factory=dict)
    spectra: Dict[str, Any] = field(default_factory=dict)
    docking_results: List[Dict[str, Any]] = field(default_factory=list)
    receptor_info: Dict[str, Any] = field(default_factory=dict)
    derivatives: List[Any] = field(default_factory=list)
    synthesis_routes: List[Any] = field(default_factory=list)
    admet_profile: Dict[str, Any] = field(default_factory=dict)
    screenshots: Dict[str, str] = field(default_factory=dict)
    ts_captures: Dict[str, str] = field(default_factory=dict)
    # ts_captures: {'reactant_path': str, 'transition_state_path': str, 'product_path': str}
    base_docking_score: float = 0.0
    goal: str = ""
    ai_analysis_text: str = ""
    # Cascade #11 Block 11-A: innate defense docking result
    innate_defense_result: Optional[Any] = None  # AntimicrobialBindingResult
    # Cascade #11 Block 11-B: membrane permeability result
    membrane_permeability_result: Optional[Any] = None  # PermeabilityResult
