def _admet_to_dict(profile):
    """Convert ADMETProfile object to dict if needed.

    The admet_profile field on DryLabData is typed as Dict, but callers
    may pass an ADMETProfile dataclass from admet_predictor.py.  This
    helper normalises both cases to a plain dict so .items() always works.
    """
    if profile is None:
        return {}
    if isinstance(profile, dict):
        return profile
    # ADMETProfile object — extract relevant fields
    result = {}
    try:
        if hasattr(profile, 'lipinski'):
            lip = profile.lipinski
            result['MW'] = getattr(lip, 'mw', 0)
            result['LogP'] = getattr(lip, 'logp', 0)
            result['HBD'] = getattr(lip, 'hbd', 0)
            result['HBA'] = getattr(lip, 'hba', 0)
            result['Lipinski_violations'] = getattr(lip, 'violations', 0)
        if hasattr(profile, 'bbb'):
            result['BBB'] = getattr(profile.bbb, 'classification', '')
        if hasattr(profile, 'tpsa'):
            result['TPSA'] = profile.tpsa
        if hasattr(profile, 'drug_likeness_score'):
            result['drug_likeness'] = profile.drug_likeness_score
        if hasattr(profile, 'oral_bioavailability'):
            result['oral_bioavailability'] = profile.oral_bioavailability
        if hasattr(profile, 'overall_assessment'):
            result['overall'] = profile.overall_assessment
    except Exception as e:
        logger.warning("ADMET profile conversion error: %s", e)
    # Fallback: try vars() / __dict__ for any dataclass-like object
    if not result:
        try:
            result = dict(vars(profile))
        except Exception as e:
            logger.warning("ADMET vars() fallback failed: %s", e)
    return result


