# ═══════════════════════════════════════════════════════════
# Helper: SMILES -> PNG bytes
# ═══════════════════════════════════════════════════════════

def _smiles_to_png(smiles: str, w: int = 300, h: int = 250,
                   dark_bg: bool = False) -> Optional[bytes]:
    """SMILES -> PNG image bytes via RDKit.

    SVG→PNG via cairosvg 우선 시도, 실패 시 Draw.MolToImage 폴백.
    """
    if not RDKIT_AVAILABLE or not PIL_AVAILABLE:
        return None
    try:
        mol = Chem.MolFromSmiles(smiles)
        if mol is None:
            logger.warning("SMILES 파싱 실패: %s", smiles)
            return None
        AllChem.Compute2DCoords(mol)

        # 방법 1: SVG → PNG (cairosvg 필요)
        svg_png = None
        try:
            import cairosvg  # noqa: F811
            drawer = Draw.MolDraw2DSVG(w, h)
            if dark_bg:
                drawer.drawOptions().setBackgroundColour((0.1, 0.1, 0.15, 1.0))
            try:
                drawer.drawOptions().atomLabelFontSize = 14
            except AttributeError as e:
                logger.debug("Attribute not available: %s", e)
            drawer.DrawMolecule(mol)
            drawer.FinishDrawing()
            svg = drawer.GetDrawingText()
            svg_png = cairosvg.svg2png(bytestring=svg.encode(), dpi=300)
        except Exception as e:
            logger.warning("_smiles_to_png failed: %s", e)
            svg_png = None

        if svg_png:
            return svg_png

        # 방법 2: RDKit Draw.MolToImage 폴백 (cairosvg 불필요)
        img = Draw.MolToImage(mol, size=(w, h))
        buf = io.BytesIO()
        img.save(buf, format="PNG")
        buf.seek(0)
        return buf.getvalue()
    except Exception as e:
        logger.warning("SMILES to PNG failed for %s: %s", smiles, e)
        return None


