def _build_receptor_data(receptor_info: dict, ligand_center: tuple = (0.0, 0.0, 0.0)):
    """Build a realistic ReceptorData object from receptor_info dict.

    Generates a protein backbone with:
    - 4 alpha-helices surrounding a central binding pocket
    - Binding site residues placed at known positions around the pocket
    - Realistic backbone atom positions (N, CA, C, O, CB per residue)

    Args:
        receptor_info: dict with 'pdb_id', 'name', 'binding_site_residues', etc.
        ligand_center: (x, y, z) center of ligand for pocket positioning

    Returns:
        (ReceptorData, list[Interaction]) tuple
    """
    try:
        from docking_data import ReceptorData, Residue, PDBAtom
    except ImportError as e:
        logger.debug("Optional module not available (docking_data): %s", e)
        import sys as _sys
        src_dir = os.path.dirname(os.path.abspath(__file__))
        if src_dir not in _sys.path:
            _sys.path.insert(0, src_dir)
        from docking_data import ReceptorData, Residue, PDBAtom

    if not isinstance(receptor_info, dict):
        logger.warning("_build_receptor_data: receptor_info is not dict (type=%s)", type(receptor_info).__name__)
        receptor_info = {}
    pdb_id = receptor_info.get("pdb_id", "UNK")
    rec_name = receptor_info.get("name", pdb_id)
    binding_labels = receptor_info.get("binding_site_residues", [])

    # Parse residue labels like "Arg120" into (name3, resid)
    import re
    parsed_binding = []
    for label in binding_labels:
        m = re.match(r"([A-Za-z]+)(\d+)'?", label)
        if m:
            parsed_binding.append((m.group(1).upper()[:3], int(m.group(2))))
        else:
            parsed_binding.append(("ALA", 999))

    lx, ly, lz = ligand_center
    all_atoms = []
    residues_by_chain = {"A": []}
    serial = 1

    # ── Step 1: Generate alpha-helix bundle (backbone) ──
    # 8 helices × 40 residues = 320 residues → dense, visible ribbon
    n_helices = 8  # 8 helices in a bundle (transmembrane-like)
    helix_residues_count = 40  # residues per helix
    helix_radius = 15.0  # Å — distance from helix center to bundle axis
    rise_per_res = 1.5  # Å — rise per residue along helix axis
    helix_angular_step = 1.745  # ~100° per residue (alpha helix)

    res_id_counter = 1
    aa_names = ["ALA", "GLY", "LEU", "VAL", "ILE", "PHE", "SER",
                "THR", "ASP", "GLU", "LYS", "ARG", "PRO", "MET"]

    for h_idx in range(n_helices):
        # Each helix positioned at a different angle around the binding pocket
        base_angle = (2.0 * math.pi * h_idx / n_helices)  # angular position of helix
        hx = lx + helix_radius * math.cos(base_angle)  # helix center x
        hy = ly + helix_radius * math.sin(base_angle)  # helix center y
        hz_start = lz - (helix_residues_count * rise_per_res) / 2.0  # centered vertically

        # Small helix radius for backbone trace (alpha-helix ~2.3 Å radius)
        local_r = 2.3  # Å — alpha helix backbone radius

        for r_idx in range(helix_residues_count):
            angle = helix_angular_step * r_idx
            # CA position along the helix
            ca_x = hx + local_r * math.cos(angle)
            ca_y = hy + local_r * math.sin(angle)
            ca_z = hz_start + rise_per_res * r_idx

            aa_name = aa_names[r_idx % len(aa_names)]

            res_atoms = []
            for atom_name, (dx, dy, dz) in _AA_BACKBONE_OFFSETS.items():
                # Rotate offsets by helix angle for variety
                cos_a, sin_a = math.cos(angle * 0.3), math.sin(angle * 0.3)
                rx = dx * cos_a - dy * sin_a
                ry = dx * sin_a + dy * cos_a
                atom = PDBAtom(
                    serial=serial, name=atom_name,
                    residue_name=aa_name, chain="A",
                    residue_id=res_id_counter,
                    x=ca_x + rx, y=ca_y + ry, z=ca_z + dz,
                    element=atom_name[0],  # N, C, O
                )
                res_atoms.append(atom)
                all_atoms.append(atom)
                serial += 1

            # Always add CA explicitly
            ca_atom = PDBAtom(
                serial=serial, name="CA",
                residue_name=aa_name, chain="A",
                residue_id=res_id_counter,
                x=ca_x, y=ca_y, z=ca_z,
                element="C",
            )
            res_atoms.insert(0, ca_atom)  # CA first
            all_atoms.append(ca_atom)
            serial += 1

            residue = Residue(
                name=aa_name, chain="A",
                residue_id=res_id_counter, atoms=res_atoms
            )
            residues_by_chain["A"].append(residue)
            res_id_counter += 1

    # ── Step 2: Place binding site residues around the pocket ──
    n_binding = len(parsed_binding)
    if n_binding > 0:
        for b_idx, (res_name_3, res_id_orig) in enumerate(parsed_binding):
            # Distribute binding residues in a shell 5-8 Å from ligand center
            theta = 2.0 * math.pi * b_idx / n_binding
            phi = math.pi * 0.3 + (math.pi * 0.4) * (b_idx / max(n_binding - 1, 1))
            bind_r = 6.0  # Å from ligand center — typical binding distance

            ca_x = lx + bind_r * math.sin(phi) * math.cos(theta)
            ca_y = ly + bind_r * math.sin(phi) * math.sin(theta)
            ca_z = lz + bind_r * math.cos(phi)

            res_atoms = []
            ca_atom = PDBAtom(
                serial=serial, name="CA",
                residue_name=res_name_3, chain="A",
                residue_id=res_id_orig,
                x=ca_x, y=ca_y, z=ca_z,
                element="C",
            )
            res_atoms.append(ca_atom)
            all_atoms.append(ca_atom)
            serial += 1

            # Add backbone atoms
            for atom_name, (dx, dy, dz) in _AA_BACKBONE_OFFSETS.items():
                atom = PDBAtom(
                    serial=serial, name=atom_name,
                    residue_name=res_name_3, chain="A",
                    residue_id=res_id_orig,
                    x=ca_x + dx, y=ca_y + dy, z=ca_z + dz,
                    element=atom_name[0],
                )
                res_atoms.append(atom)
                all_atoms.append(atom)
                serial += 1

            residue = Residue(
                name=res_name_3, chain="A",
                residue_id=res_id_orig, atoms=res_atoms
            )
            residues_by_chain["A"].append(residue)

    receptor = ReceptorData(
        pdb_id=pdb_id, name=rec_name,
        atoms=all_atoms, residues=residues_by_chain,
    )
    return receptor


def _build_ligand_pose(smiles: str) -> Optional[tuple]:
    """Generate 3D ligand coordinates using RDKit ETKDG.

    Returns:
        (DockingPose, ligand_center) tuple or None on failure.
        ligand_center is (x, y, z) centroid of the ligand.
    """
    if not RDKIT_AVAILABLE:
        return None
    try:
        from docking_data import DockingPose
    except ImportError as e:
        logger.debug("Optional module not available (docking_data): %s", e)
        import sys as _sys
        src_dir = os.path.dirname(os.path.abspath(__file__))
        if src_dir not in _sys.path:
            _sys.path.insert(0, src_dir)
        from docking_data import DockingPose

    try:
        mol = Chem.MolFromSmiles(smiles)
        if mol is None:
            logger.warning("SMILES 파싱 실패: %s", smiles)
            return None
        mol = Chem.AddHs(mol)
        params = AllChem.ETKDGv3()
        params.randomSeed = 42  # reproducible embedding
        status = AllChem.EmbedMolecule(mol, params)
        if status != 0:
            # Fallback: use random coordinates
            AllChem.EmbedMolecule(mol, AllChem.ETKDGv3(),
                                  randomSeed=42, useRandomCoords=True)
        try:
            AllChem.MMFFOptimizeMolecule(mol, maxIters=500)
        except Exception as e:
            logger.warning("_build_ligand_pose failed: %s", e)
            try:
                AllChem.UFFOptimizeMolecule(mol, maxIters=500)
            except Exception as e:
                logger.warning("_build_ligand_pose failed: %s", e)

        conf = mol.GetConformer()
        # Remove explicit H for cleaner visualization
        heavy_mol = Chem.RemoveHs(mol)
        heavy_conf = heavy_mol.GetConformer()

        coords = []
        elements = []
        for idx in range(heavy_mol.GetNumAtoms()):
            pos = heavy_conf.GetAtomPosition(idx)
            coords.append((pos.x, pos.y, pos.z))
            elements.append(heavy_mol.GetAtomWithIdx(idx).GetSymbol())

        # Compute centroid
        cx = sum(c[0] for c in coords) / len(coords)
        cy = sum(c[1] for c in coords) / len(coords)
        cz = sum(c[2] for c in coords) / len(coords)

        pose = DockingPose(
            pose_id=1,
            affinity_kcal=-7.5,  # reasonable mock binding energy (kcal/mol)
            atom_coords=coords,
            atom_elements=elements,
            smiles=smiles,
        )
        return pose, (cx, cy, cz)
    except Exception as e:
        logger.debug("Ligand pose generation failed: %s", e)
        return None


def _build_interactions(receptor_info: dict, ligand_coords: list,
                        ligand_elements: list, ligand_center: tuple):
    """Generate realistic protein-ligand interactions from binding site info.

    Assigns H-bond vs hydrophobic based on residue type and closest ligand atom element.

    Returns:
        list of Interaction objects
    """
    try:
        from docking_data import Interaction
    except ImportError as e:
        logger.debug("Optional module not available (docking_data): %s", e)
        import sys as _sys
        src_dir = os.path.dirname(os.path.abspath(__file__))
        if src_dir not in _sys.path:
            _sys.path.insert(0, src_dir)
        from docking_data import Interaction

    import re
    if not isinstance(receptor_info, dict):
        logger.warning("_build_interactions: receptor_info is not dict (type=%s)", type(receptor_info).__name__)
        receptor_info = {}
    binding_labels = receptor_info.get("binding_site_residues", [])
    interactions = []

    n_binding = len(binding_labels)
    if n_binding == 0 or not ligand_coords:
        return interactions

    lx, ly, lz = ligand_center

    for b_idx, label in enumerate(binding_labels):
        m = re.match(r"([A-Za-z]+)(\d+)'?", label)
        if not m:
            continue
        res_name_3 = m.group(1).upper()[:3]
        res_id = int(m.group(2))

        # Position of this binding residue (same geometry as _build_receptor_data)
        theta = 2.0 * math.pi * b_idx / n_binding
        phi = math.pi * 0.3 + (math.pi * 0.4) * (b_idx / max(n_binding - 1, 1))
        bind_r = 6.0  # Å
        rx = lx + bind_r * math.sin(phi) * math.cos(theta)
        ry = ly + bind_r * math.sin(phi) * math.sin(theta)
        rz = lz + bind_r * math.cos(phi)

        # Find closest ligand atom
        best_dist = float('inf')
        best_idx = 0
        for a_idx, (ax, ay, az) in enumerate(ligand_coords):
            d = math.sqrt((ax - rx) ** 2 + (ay - ry) ** 2 + (az - rz) ** 2)
            if d < best_dist:
                best_dist = d
                best_idx = a_idx

        # Determine interaction type from residue name and ligand atom
        short_name = res_name_3.capitalize()
        lig_elem = ligand_elements[best_idx] if best_idx < len(ligand_elements) else "C"

        is_polar_residue = (short_name in _HBOND_RESIDUES["donor"] or
                            short_name in _HBOND_RESIDUES["acceptor"])
        is_polar_ligand = lig_elem in ("N", "O", "S", "F")

        if is_polar_residue and is_polar_ligand:
            itype = "hydrogen_bond"
        elif short_name in ("Phe", "Tyr", "Trp", "His") and lig_elem == "C":
            itype = "pi_stacking"
        elif short_name in ("Asp", "Glu") and lig_elem == "N":
            itype = "salt_bridge"
        else:
            itype = "hydrophobic"

        interactions.append(Interaction(
            type=itype,
            ligand_atom_idx=best_idx,
            protein_atom_name="CA",
            residue_name=res_name_3,
            residue_id=res_id,
            chain="A",
            distance=best_dist,
        ))

    return interactions


def _render_docking_3d_widget(receptor_info: dict, smiles: str,
                               zoom: float = 1.0,
                               rot_x: float = -20.0, rot_y: float = 30.0,
                               show_interactions: bool = False,
                               width: int = 800, height: int = 600
                               ) -> Optional[bytes]:
    """Render a docking 3D view using the real Docking3DViewerWidget.

    Creates a headless widget, feeds it real receptor + ligand data,
    captures the rendered output as PNG bytes.

    Args:
        receptor_info: dict with 'pdb_id', 'name', 'binding_site_residues'
        smiles: ligand SMILES string
        zoom: view zoom level (1.0=full, 3.0-5.0=binding site zoom)
        rot_x, rot_y: rotation angles in degrees
        show_interactions: whether to render interaction lines
        width, height: output image dimensions in pixels

    Returns:
        PNG image bytes or None on failure
    """
    if not isinstance(receptor_info, dict):
        logger.warning("_render_docking_3d_widget: receptor_info is not dict (type=%s)", type(receptor_info).__name__)
        receptor_info = {}

    # Skip QWidget/OpenGL path in offscreen mode — it can hang indefinitely
    # because OpenGL context creation may block without a real display.
    _qpa = os.environ.get("QT_QPA_PLATFORM", "").lower()
    if _qpa == "offscreen":
        logger.info(
            "_render_docking_3d_widget: skipping QWidget path (QT_QPA_PLATFORM=offscreen), "
            "falling back to matplotlib"
        )
        return _render_3d_docking_matplotlib(
            receptor_info=receptor_info,
            smiles=smiles,
            show_interactions=show_interactions,
            mode="full",
            width=width,
            height=height,
        )

    try:
        from PyQt6.QtWidgets import QApplication
        from PyQt6.QtCore import Qt
        from PyQt6.QtGui import QColor

        try:
            from docking_3d_viewer import Docking3DViewerWidget
        except ImportError as e:
            logger.debug("Optional module not available (docking_3d_viewer): %s", e)
            import sys as _sys
            src_dir = os.path.dirname(os.path.abspath(__file__))
            if src_dir not in _sys.path:
                _sys.path.insert(0, src_dir)
            from docking_3d_viewer import Docking3DViewerWidget

        # Ensure QApplication exists (required for QWidget)
        app = QApplication.instance()
        if app is None:
            app = QApplication([])

        # Build ligand pose from SMILES
        pose_result = _build_ligand_pose(smiles)
        if pose_result is None:
            logger.warning("도킹 포즈 결과 없음: pose_result is None")
            return None
        pose, ligand_center = pose_result

        # Build receptor data centered around ligand
        receptor = _build_receptor_data(receptor_info, ligand_center)

        # Build interactions
        interactions = _build_interactions(
            receptor_info, pose.atom_coords, pose.atom_elements, ligand_center)

        # Build binding site residue tuples for set_data
        import re
        if not isinstance(receptor_info, dict):  # Rule N: type guard
            receptor_info = {}
        binding_labels = receptor_info.get("binding_site_residues", [])
        binding_site_tuples = []
        for label in binding_labels:
            m = re.match(r"([A-Za-z]+)(\d+)'?", label)
            if m:
                res_3 = m.group(1).upper()[:3]
                res_id = int(m.group(2))
                short = m.group(1).capitalize()
                is_donor = short in _HBOND_RESIDUES.get("donor", set())
                is_acceptor = short in _HBOND_RESIDUES.get("acceptor", set())
                binding_site_tuples.append((res_3, res_id, "A", is_donor, is_acceptor))

        # Create headless widget
        widget = Docking3DViewerWidget()
        widget.setAttribute(Qt.WidgetAttribute.WA_DontShowOnScreen)
        widget.resize(width, height)

        # White background for PDF output
        widget._bg_color = QColor(255, 255, 255)

        # Set view parameters
        widget.zoom = zoom
        widget.rot_x = rot_x
        widget.rot_y = rot_y
        widget.show_protein = True
        widget.show_ligand = True
        widget.show_binding_site = True
        widget.show_interactions = show_interactions

        # Feed data to widget
        widget.set_data(
            receptor=receptor,
            pose=pose,
            interactions=interactions,
            binding_site_residues=binding_site_tuples if binding_site_tuples else None,
        )

        # Force layout and render
        widget.show()
        widget.update()
        widget.repaint()

        # Capture rendered image
        pixmap = widget.grab()
        widget.close()

        # Convert QPixmap to PNG bytes
        buf = io.BytesIO()
        qbuf = pixmap.toImage()
        ba = pixmap.toImage()

        # Use QBuffer for conversion
        from PyQt6.QtCore import QBuffer, QIODevice
        qbyte_array = __import__('PyQt6.QtCore', fromlist=['QByteArray']).QByteArray()
        qbuffer = QBuffer(qbyte_array)
        qbuffer.open(QIODevice.OpenModeFlag.WriteOnly)
        pixmap.save(qbuffer, "PNG")
        qbuffer.close()

        png_bytes = bytes(qbyte_array)
        if len(png_bytes) < 100:  # too small = empty/failed render
            logger.debug("Docking 3D render too small (%d bytes)", len(png_bytes))
            return None
        return png_bytes

    except Exception as e:
        logger.warning(
            "Docking3DViewerWidget render failed (OpenGL/headless): %s — "
            "falling back to matplotlib 3D rendering", e
        )
        return _render_3d_docking_matplotlib(
            receptor_info=receptor_info,
            smiles=smiles,
            show_interactions=show_interactions,
            mode="full",
            width=width,
            height=height,
        )


def _render_3d_docking_matplotlib(
        receptor_info: dict,
        smiles: str,
        show_interactions: bool = False,
        mode: str = "full",   # "full" | "binding_site" | "ribbon"
        width: int = 800,
        height: int = 600,
) -> Optional[bytes]:
    """Publication-quality 3D docking image using matplotlib + RDKit 3D coords.

    Works headlessly (no OpenGL / display required).

    Rendering:
    - Ligand: CPK-colored ball-and-stick (RDKit ETKDG + MMFF)
    - Receptor binding-site residues: Cα positions as grey spheres + labels
    - Interactions: dashed coloured lines (H-bond=blue, hydrophobic=orange,
      pi-stacking=green, salt-bridge=red)
    - Footer note: "이론적 3D 렌더링 (matplotlib 기반)"
    - White background, high-DPI

    Args:
        receptor_info: dict with 'name', 'pdb_id', 'binding_site_residues'
        smiles:        ligand SMILES
        show_interactions: draw protein-ligand interaction lines
        mode:          "full" = full view, "binding_site" = zoomed pocket,
                       "ribbon" = receptor-centric
        width, height: output pixel dimensions

    Returns:
        PNG bytes or None on failure.
    """
    if not isinstance(receptor_info, dict):
        logger.warning("_render_3d_docking_matplotlib: receptor_info is not dict (type=%s)", type(receptor_info).__name__)
        receptor_info = {}
    if not MATPLOTLIB_AVAILABLE or not RDKIT_AVAILABLE:
        logger.warning("matplotlib or RDKit unavailable — cannot generate 3D matplotlib docking image")
        return None

    try:
        import numpy as np
        from mpl_toolkits.mplot3d import Axes3D  # noqa: F401 (registers 3d projection)

        # ── 1. Generate ligand 3D coordinates ────────────────────────────────
        mol = Chem.MolFromSmiles(smiles)
        if mol is None:
            logger.warning("_render_3d_docking_matplotlib: invalid SMILES '%s'", smiles)
            return None
        mol = Chem.AddHs(mol)
        params = AllChem.ETKDGv3()
        params.randomSeed = 42
        status = AllChem.EmbedMolecule(mol, params)
        if status != 0:
            AllChem.EmbedMolecule(mol, AllChem.ETKDGv3(),
                                  randomSeed=42, useRandomCoords=True)
        try:
            AllChem.MMFFOptimizeMolecule(mol, maxIters=500)
        except Exception as e:
            logger.warning("Operation failed: %s", e)
            try:
                AllChem.UFFOptimizeMolecule(mol, maxIters=500)
            except Exception as e:
                logger.warning("Operation failed: %s", e)

        heavy_mol = Chem.RemoveHs(mol)
        conf = heavy_mol.GetConformer()
        lig_coords = np.array([conf.GetAtomPosition(i) for i in range(heavy_mol.GetNumAtoms())])
        lig_elements = [heavy_mol.GetAtomWithIdx(i).GetSymbol() for i in range(heavy_mol.GetNumAtoms())]

        # CPK colour map
        _CPK = {
            'C': '#404040', 'N': '#3050F8', 'O': '#FF0D0D',
            'F': '#90E050', 'Cl': '#1FF01F', 'Br': '#A62929',
            'I': '#940094', 'S': '#FFFF30', 'P': '#FF8000',
            'H': '#FFFFFF',
        }
        if not isinstance(_CPK, dict):  # Rule N: type guard
            _CPK = {}
        lig_colors = [_CPK.get(e, '#FF69B4') for e in lig_elements]
        lig_sizes = [320 if e != 'H' else 80 for e in lig_elements]

        ligand_center = lig_coords.mean(axis=0)
        lx, ly, lz = ligand_center

        if not isinstance(receptor_info, dict):  # Rule N: type guard
            receptor_info = {}
        # ── 2. Receptor binding-site residue Cα positions ────────────────────
        binding_labels = receptor_info.get("binding_site_residues", []) or []
        n_binding = len(binding_labels)

        receptor_ca = []   # list of (x, y, z, label)
        import re as _re
        for b_idx, label in enumerate(binding_labels):
            m = _re.match(r"([A-Za-z]+)(\d+)'?", label)
            if not m:
                continue
            theta = 2.0 * math.pi * b_idx / max(n_binding, 1)
            phi = math.pi * 0.3 + math.pi * 0.4 * (b_idx / max(n_binding - 1, 1))
            bind_r = 6.0  # Å — typical binding pocket radius
            rx = lx + bind_r * math.sin(phi) * math.cos(theta)
            ry = ly + bind_r * math.sin(phi) * math.sin(theta)
            rz = lz + bind_r * math.cos(phi)
            short_name = m.group(1).capitalize()
            res_id = m.group(2)
            receptor_ca.append((rx, ry, rz, f"{short_name}{res_id}"))

        # ── 3. Build figure ───────────────────────────────────────────────────
        dpi = 150
        fig_w = width / dpi
        fig_h = height / dpi
        fig = plt.figure(figsize=(fig_w, fig_h), dpi=dpi)
        ax = fig.add_subplot(111, projection='3d')
        fig.patch.set_facecolor('white')

        # ── 4. Draw ligand bonds ─────────────────────────────────────────────
        for bond in heavy_mol.GetBonds():
            i, j = bond.GetBeginAtomIdx(), bond.GetEndAtomIdx()
            xs = [lig_coords[i][0], lig_coords[j][0]]
            ys = [lig_coords[i][1], lig_coords[j][1]]
            zs = [lig_coords[i][2], lig_coords[j][2]]
            bo = bond.GetBondTypeAsDouble()
            lw = 3.0 if bo > 1.5 else 2.0 if bo > 1.0 else 1.5
            ax.plot(xs, ys, zs, color='#555555', linewidth=lw, zorder=3)

        # ── 5. Draw ligand atoms ─────────────────────────────────────────────
        for idx in range(heavy_mol.GetNumAtoms()):
            ax.scatter(
                lig_coords[idx][0], lig_coords[idx][1], lig_coords[idx][2],
                c=lig_colors[idx], s=lig_sizes[idx],
                edgecolors='#222222', linewidths=0.6,
                zorder=4, depthshade=True,
            )

        # ── 6. Draw receptor Cα residues ─────────────────────────────────────
        if mode != "ribbon":
            _res_color = '#AAAAAA'  # neutral grey for receptor
            for rx, ry, rz, lbl in receptor_ca:
                ax.scatter(rx, ry, rz, c=_res_color, s=180,
                           edgecolors='#666666', linewidths=0.5,
                           zorder=2, depthshade=True, marker='o')
                ax.text(rx, ry, rz + 0.3, lbl, fontsize=5,
                        color='#444444', ha='center', va='bottom',
                        zorder=5)

        # ── 7. Draw interaction lines ─────────────────────────────────────────
        if show_interactions and receptor_ca:
            _itype_color = {
                'hydrogen_bond': '#2255FF',
                'hydrophobic':   '#FF8800',
                'pi_stacking':   '#22BB22',
                'salt_bridge':   '#DD2222',
            }
            # Use closest CA to each polar ligand atom as a simple H-bond proxy
            polar_idxs = [i for i, e in enumerate(lig_elements) if e in ('N', 'O', 'S', 'F')]
            hbond_pairs = min(len(polar_idxs), len(receptor_ca))
            for k in range(hbond_pairs):
                li = polar_idxs[k]
                rx, ry, rz, _ = receptor_ca[k % len(receptor_ca)]
                itype = 'hydrogen_bond'
                color = _itype_color[itype]
                ax.plot(
                    [lig_coords[li][0], rx],
                    [lig_coords[li][1], ry],
                    [lig_coords[li][2], rz],
                    color=color, linewidth=1.2,
                    linestyle='--', alpha=0.7, zorder=1,
                )
            # Hydrophobic — connect remaining CA positions to nearest C atom
            c_idxs = [i for i, e in enumerate(lig_elements) if e == 'C']
            for k in range(hbond_pairs, len(receptor_ca)):
                if not c_idxs:
                    break
                li = c_idxs[k % len(c_idxs)]
                rx, ry, rz, _ = receptor_ca[k]
                ax.plot(
                    [lig_coords[li][0], rx],
                    [lig_coords[li][1], ry],
                    [lig_coords[li][2], rz],
                    color=_itype_color['hydrophobic'], linewidth=1.0,
                    linestyle=':', alpha=0.5, zorder=1,
                )

        if not isinstance(receptor_info, dict):  # Rule N: type guard
            receptor_info = {}
        # ── 8. Title and styling ──────────────────────────────────────────────
        rec_name = receptor_info.get("name", receptor_info.get("pdb_id", "Receptor"))
        mode_label = {
            "full": "도킹 전체 뷰",
            "binding_site": "결합부위 확대",
            "ribbon": "수용체 리본 구조",
        }.get(mode, "3D 도킹 뷰")
        fontprop = _get_mpl_fontprop()
        ax.set_title(
            f"{rec_name} — {mode_label}",
            fontsize=9, pad=2, fontproperties=fontprop,
        )
        ax.set_axis_off()
        ax.set_box_aspect([1, 1, 1])

        # Footer note
        fig.text(
            0.5, 0.01,
            "이론적 3D 렌더링 (matplotlib 기반) — OpenGL 렌더러 미사용",
            ha='center', fontsize=6, color='#777777',
            fontproperties=fontprop,
        )

        fig.tight_layout(pad=0.3)
        buf = io.BytesIO()
        fig.savefig(buf, format="PNG", bbox_inches="tight",
                    facecolor='white', dpi=dpi)
        plt.close(fig)
        buf.seek(0)
        return buf.getvalue()

    except Exception as e:
        logger.warning("_render_3d_docking_matplotlib failed: %s", e)
        return None


def _generate_receptor_ribbon_png(receptor_info: dict,
                                   ligand_smiles: str = "") -> Optional[bytes]:
    """Generate a full receptor ribbon diagram.

    Tries the real Docking3DViewerWidget first; falls back to
    matplotlib-based 3D rendering if the widget is unavailable (headless).
    White background suitable for PDF embedding.

    Returns PNG bytes or None.
    """
    result = _render_docking_3d_widget(
        receptor_info=receptor_info,
        smiles=ligand_smiles or "C",  # fallback to methane if no SMILES
        zoom=1.5,          # slightly zoomed to fill frame
        rot_x=-25.0,       # tilt for 3D depth perception
        rot_y=45.0,        # rotated for best ribbon visibility
        show_interactions=False,  # clean ribbon view without interaction lines
        width=800,         # px — high resolution for PDF
        height=600,        # px
    )
    if result is not None:
        return result
    # Secondary fallback: explicit matplotlib ribbon mode
    logger.warning("_generate_receptor_ribbon_png: widget returned None, using matplotlib ribbon mode")
    return _render_3d_docking_matplotlib(
        receptor_info=receptor_info,
        smiles=ligand_smiles or "C",
        show_interactions=False,
        mode="ribbon",
        width=800,
        height=600,
    )


def _generate_docking_binding_site_png(smiles: str,
                                        receptor_info: dict) -> Optional[bytes]:
    """Generate a zoomed-in binding site view.

    Tries the real Docking3DViewerWidget first; falls back to
    matplotlib-based 3D rendering if the widget is unavailable (headless).
    Shows ligand docked into receptor binding pocket with interaction lines.
    White background suitable for PDF embedding.

    Returns PNG bytes or None.
    """
    if not smiles:
        return None
    result = _render_docking_3d_widget(
        receptor_info=receptor_info,
        smiles=smiles,
        zoom=4.0,          # zoomed into binding site
        rot_x=-15.0,       # slight angle for depth
        rot_y=45.0,        # rotated for better pocket visibility
        show_interactions=True,  # show H-bond/hydrophobic lines
        width=800,         # px
        height=600,        # px
    )
    if result is not None:
        return result
    # Secondary fallback: explicit matplotlib binding_site mode
    logger.warning("_generate_docking_binding_site_png: widget returned None, using matplotlib binding_site mode")
    return _render_3d_docking_matplotlib(
        receptor_info=receptor_info,
        smiles=smiles,
        show_interactions=True,
        mode="binding_site",
        width=800,
        height=600,
    )


def _generate_3d_ball_stick_png(smiles: str) -> Optional[bytes]:
    """Generate a 3D ball-and-stick style image using RDKit + matplotlib.

    Embeds 3D coordinates via ETKDG and renders a CPK-colored
    scatter plot with bond lines, viewed from an isometric angle.
    """
    if not RDKIT_AVAILABLE or not MATPLOTLIB_AVAILABLE or not PIL_AVAILABLE:
        return None
    try:
        mol = Chem.MolFromSmiles(smiles)
        if mol is None:
            logger.warning("SMILES 파싱 실패: %s", smiles)
            return None
        mol = Chem.AddHs(mol)
        status = AllChem.EmbedMolecule(mol, AllChem.ETKDGv3())
        if status != 0:
            AllChem.EmbedMolecule(mol, AllChem.ETKDGv3(),
                                  randomSeed=42, useRandomCoords=True)
        try:
            AllChem.MMFFOptimizeMolecule(mol, maxIters=500)
        except Exception as e:
            logger.warning("_generate_3d_ball_stick_png failed: %s", e)
            try:
                AllChem.UFFOptimizeMolecule(mol, maxIters=500)
            except Exception as e:
                logger.warning("_generate_3d_ball_stick_png failed: %s", e)

        conf = mol.GetConformer()
        coords = conf.GetPositions()

        # CPK coloring
        cpk = {6: '#333333', 1: '#FFFFFF', 7: '#3050F8', 8: '#FF0D0D',
               9: '#90E050', 15: '#FF8000', 16: '#FFFF30', 17: '#1FF01F',
               35: '#A62929', 53: '#940094'}
        atom_colors = []
        atom_sizes = []
        for atom in mol.GetAtoms():
            an = atom.GetAtomicNum()
            if not isinstance(cpk, dict):  # Rule N: type guard
                cpk = {}
            atom_colors.append(cpk.get(an, '#FF69B4'))
            atom_sizes.append(120 if an == 1 else 280)

        fig = plt.figure(figsize=(6, 5), dpi=200)
        ax = fig.add_subplot(111, projection='3d')

        # Draw bonds
        for bond in mol.GetBonds():
            i, j = bond.GetBeginAtomIdx(), bond.GetEndAtomIdx()
            xs = [coords[i][0], coords[j][0]]
            ys = [coords[i][1], coords[j][1]]
            zs = [coords[i][2], coords[j][2]]
            lw = 2.5 if bond.GetBondTypeAsDouble() > 1 else 1.5
            ax.plot(xs, ys, zs, color='#555555', linewidth=lw, zorder=1)

        # Draw atoms
        for idx in range(mol.GetNumAtoms()):
            ax.scatter(coords[idx][0], coords[idx][1], coords[idx][2],
                       c=atom_colors[idx], s=atom_sizes[idx],
                       edgecolors='#333333', linewidths=0.5, zorder=2,
                       depthshade=True)

        ax.set_axis_off()
        ax.set_box_aspect([1, 1, 1])
        fig.patch.set_facecolor('white')

        fontprop = _get_mpl_fontprop()
        title = "3D Ball-and-Stick Model"
        ax.set_title(title, fontsize=10, pad=-5,
                     fontproperties=fontprop)

        fig.tight_layout(pad=0)
        buf = io.BytesIO()
        fig.savefig(buf, format="PNG", bbox_inches="tight",
                    facecolor='white', dpi=200)
        plt.close(fig)
        buf.seek(0)
        return buf.getvalue()
    except Exception as e:
        logger.debug("3D ball-stick gen failed: %s", e)
        return None


def _generate_reaction_scheme_png(smiles: str, name: str = "") -> Optional[bytes]:
    """Generate a 2D reaction scheme image: Reactant → [conditions] → Product.

    For allicin (or thiosulfinate), draws DADS + mCPBA → Allicin.
    For other molecules, draws a generic scheme with the product.
    Returns PNG bytes or None.
    """
    if not RDKIT_AVAILABLE or not PIL_AVAILABLE:
        return None
    try:
        from PIL import Image as PILImage, ImageDraw, ImageFont

        # Determine if allicin-like (thiosulfinate)
        smiles_lower = (smiles or "").upper()
        is_allicin = ("S(=O)S" in smiles or "SS(=O)" in smiles
                       or "allicin" in (name or "").lower()
                       or "C=CCSS" in smiles)

        if is_allicin:
            reactant_smiles = "C=CCSSC=C"  # DADS
            product_smiles = smiles
            reactant_label = "DADS\n(Diallyl disulfide)"
            product_label = name or "Allicin"
            condition_text = "mCPBA, DCM\n-20\u2103, 1h"
        else:
            # Generic: show product with a generic reactant placeholder
            product_smiles = smiles
            product_label = name or "Product"
            # Try to get a simpler precursor via retrosynthesis
            reactant_smiles = None
            reactant_label = "Starting Material"
            condition_text = "Reagent\nSolvent, Temp"
            try:
                if _HEADLESS_MODE:
                    # [M756 F6-6-RESIDUAL] offscreen/CI 환경에서 retrosynthesis skip
                    # — RetrosynthesisEngine.find_routes()는 GUI 없이 수십 초 걸릴 수 있음
                    logger.warning(
                        "_generate_reaction_scheme_png: HEADLESS_MODE — retrosynthesis skipped"
                    )
                    routes = []
                else:
                    from retrosynthesis_engine import RetrosynthesisEngine
                    engine = RetrosynthesisEngine()
                    # [M756 F6-6-RESIDUAL] timeout wrap 8s — AV F6-6 COND_PASS 잔존 fix
                    routes = _run_with_timeout(
                        lambda: engine.find_routes(smiles),
                        timeout_sec=8.0,
                        default=[],
                    )
                if routes and hasattr(routes[0], 'steps') and routes[0].steps:
                    first_step = routes[0].steps[0]
                    reactant_smiles = getattr(first_step, 'reactant', None)
                    reagent = getattr(first_step, 'reagent', '')
                    cond = getattr(first_step, 'conditions', '')
                    if reagent or cond:
                        condition_text = f"{reagent}\n{cond}" if cond else reagent
                    if hasattr(first_step, 'reactant_name') and first_step.reactant_name:
                        reactant_label = first_step.reactant_name
            except Exception as e:
                logger.warning("_generate_reaction_scheme_png failed: %s", e)

        # Draw molecules using RDKit
        product_mol = Chem.MolFromSmiles(product_smiles)
        reactant_mol = Chem.MolFromSmiles(reactant_smiles) if reactant_smiles else None
        if reactant_mol is None and reactant_smiles:
            logger.warning("Invalid SMILES for DryLab reactant in scheme: %s", reactant_smiles)

        if product_mol is None:
            logger.warning("생성물 mol 파싱 실패: product_mol is None")
            return None

        mol_img_size = (300, 200)
        if reactant_mol is not None:
            mols = [reactant_mol, product_mol]
            grid_img = Draw.MolsToGridImage(
                mols, molsPerRow=2, subImgSize=mol_img_size,
                legends=[reactant_label, product_label])
        else:
            grid_img = Draw.MolsToGridImage(
                [product_mol], molsPerRow=1, subImgSize=mol_img_size,
                legends=[product_label])

        # Convert to PIL for annotation
        if hasattr(grid_img, 'convert'):
            pil_img = grid_img.convert('RGB')
        else:
            buf_tmp = io.BytesIO()
            grid_img.save(buf_tmp, format='PNG')
            buf_tmp.seek(0)
            pil_img = PILImage.open(buf_tmp).convert('RGB')

        # Create final canvas with arrow and conditions
        w, h = pil_img.size
        canvas_w = w + 60  # extra space
        canvas_h = h + 60  # space for condition text below arrow
        canvas = PILImage.new('RGB', (canvas_w, canvas_h), 'white')
        canvas.paste(pil_img, (30, 10))

        draw = ImageDraw.Draw(canvas)

        # Draw reaction arrow between the two molecules
        if reactant_mol is not None:
            arrow_y = h // 2 + 10
            arrow_x_start = w // 2 - 40 + 30
            arrow_x_end = w // 2 + 40 + 30
            # Arrow shaft
            draw.line([(arrow_x_start, arrow_y), (arrow_x_end, arrow_y)],
                      fill='black', width=3)
            # Arrow head
            draw.polygon([
                (arrow_x_end, arrow_y),
                (arrow_x_end - 10, arrow_y - 7),
                (arrow_x_end - 10, arrow_y + 7),
            ], fill='black')

            # Condition text above arrow (Korean-capable font)
            font = _get_pil_font(12)

            cond_lines = condition_text.split('\n')
            text_y = arrow_y - 18 * len(cond_lines) - 5
            for cl in cond_lines:
                bbox = draw.textbbox((0, 0), cl, font=font)
                tw = bbox[2] - bbox[0]
                tx = (arrow_x_start + arrow_x_end) // 2 - tw // 2
                draw.text((tx, text_y), cl, fill='black', font=font)
                text_y += 18

        buf = io.BytesIO()
        canvas.save(buf, format='PNG', dpi=(200, 200))
        buf.seek(0)
        return buf.getvalue()
    except Exception as e:
        logger.debug("Reaction scheme gen failed: %s", e)
        return None


def _draw_curved_arrow(draw, x1: int, y1: int, x2: int, y2: int,
                       color: str = '#cc0000', width: int = 6,
                       direction: str = 'up', half_head: bool = False,
                       atom_clearance: int = 22,
                       extra_perp_offset: int = 0,
                       arrow_label: str = '',
                       show_electron_count: bool = False,
                       is_cross_fragment: bool = False) -> None:
    """Draw a textbook-quality curved electron-pushing arrow from (x1,y1) to (x2,y2).

    교과서급 유기화학 굽은 화살표 렌더링 (Moloney/Clayden 스타일).
    - 2전자 이동: 꽉 찬 삼각형 촉머리 (half_head=False)
    - 1전자 이동: 반쪽 촉머리 (half_head=True)
    direction: 'up' = 위로 휨, 'down' = 아래로 휨
    atom_clearance: 원자에서 화살표 시작/끝점 여백 (22px)
    arrow_label: 화살표 근처에 표시할 텍스트
    show_electron_count: False(기본) — 교과서에는 전자 수 라벨 없음. True로 설정 시 "2e⁻"/"1e⁻" 표시
    is_cross_fragment: True이면 inter-fragment 화살표 — 더 밝은 빨강, 두꺼운 선, 완만한 곡률
    """
    # ── Inter-fragment vs Intra-fragment visual distinction ──
    # Cross-fragment arrows: wider, brighter red, flatter curvature (longer travel distance)
    # Intra-fragment arrows: default parameters (narrower, darker red)
    if is_cross_fragment:
        color = '#cc0000'   # bright red for inter-fragment
        width = max(width, 6)  # minimum 6px width for visual prominence
        show_electron_count = True  # always show "2e⁻" on cross-fragment arrows
        # Curvature ratio override is handled below (0.15 for long inter-fragment)
    else:
        # Intra-fragment: keep passed color, ensure slightly thinner
        if color == '#cc0000' and not is_cross_fragment:
            color = '#880000'  # darker red for intra-fragment (only if default red)
    import math
    dx, dy = x2 - x1, y2 - y1
    length = math.sqrt(dx * dx + dy * dy) or 1

    # ── 원자 여백(atom_clearance): 시작/끝점을 원자 중심에서 떼어놓기 ──
    # canvas.py draw_bond()가 get_bond_gap()으로 결합선을 원소기호에서 떼놓듯이,
    # 곡선 화살표도 원자 중심에서 22px 안쪽으로 수축하여 겹침 방지
    if length > atom_clearance * 2.5:  # 55px 미만이면 보정 안 함 (화살표가 너무 짧아짐)
        shrink = atom_clearance / length
        x1 = x1 + dx * shrink
        y1 = y1 + dy * shrink
        x2 = x2 - dx * shrink
        y2 = y2 - dy * shrink
        dx, dy = x2 - x1, y2 - y1
        length = math.sqrt(dx * dx + dy * dy) or 1

    # ── 수직 오프셋: 화살표를 결합선에서 떼어놓기 ──
    # 결합선 위에 화살표가 겹치는 문제 해결 — 시작/끝점을 곡선 방향으로 약간 이동
    # TASK-MECH-082: extra_perp_offset으로 겹치는 화살표를 추가 분리
    perp_offset = 3 + extra_perp_offset  # 3px base + anti-collision offset (Moloney: 시작점이 론페어/결합에서 직접 출발)
    perp_nx, perp_ny = -dy / length, dx / length  # 법선 벡터
    if direction == 'down':
        perp_nx, perp_ny = -perp_nx, -perp_ny
    x1 = x1 + perp_nx * perp_offset
    y1 = y1 + perp_ny * perp_offset
    x2 = x2 + perp_nx * perp_offset
    y2 = y2 + perp_ny * perp_offset
    # dx, dy 재계산
    dx, dy = x2 - x1, y2 - y1
    length = math.sqrt(dx * dx + dy * dy) or 1

    # 곡률: Moloney 교과서 스타일 — 우아하고 절제된 커브 (15-25% 비율)
    # Cross-fragment arrows: flatter curvature (0.15-0.20) for longer travel distances
    if is_cross_fragment:
        # Inter-fragment: flatter arc — travels longer distance across fragment gap
        if length < 120:
            curve_h = length * 0.25  # short cross-fragment: moderate curve
        elif length < 300:
            curve_h = length * 0.18  # medium: flatter
        else:
            curve_h = min(length * 0.15, 45)  # long: very flat arc
    elif length < 80:
        curve_h = length * 0.30  # 가까운 원자: 절제된 커브 (기존 0.45 과도)
    elif length < 200:
        curve_h = length * 0.22  # 중간 거리: 우아한 아크 (기존 0.30)
    else:
        curve_h = min(length * 0.15, 50)  # 먼 거리: 완만 (기존 0.20, cap 60→50)
    # TASK-MECH-082: 겹침 방지 — extra offset이 있으면 곡률도 증가시켜 분리 강화
    if extra_perp_offset > 0:
        curve_h += extra_perp_offset * 1.5  # 12px offset → +18px 곡률
    mid_x = (x1 + x2) / 2
    mid_y = (y1 + y2) / 2
    # 수직 방향 오프셋 → 제어점
    nx, ny = -dy / length, dx / length  # 법선 벡터
    if direction == 'up':
        cx = mid_x + nx * curve_h
        cy = mid_y + ny * curve_h
    else:
        cx = mid_x - nx * curve_h
        cy = mid_y - ny * curve_h

    # 고해상도 Bezier (50 세그먼트 → 매끄러운 곡선)
    n_seg = 50  # 50 segments for smoother curves
    pts = []
    for i in range(n_seg + 1):
        t = i / n_seg
        bx = (1 - t) ** 2 * x1 + 2 * (1 - t) * t * cx + t ** 2 * x2
        by = (1 - t) ** 2 * y1 + 2 * (1 - t) * t * cy + t ** 2 * y2
        pts.append((bx, by))

    # 촉머리 길이 — 화살표 끝에서 촉머리가 차지하는 비율
    head_len = 18  # px (larger arrowhead for clarity)
    # 촉머리 시작 지점 찾기 (끝에서 head_len만큼 거슬러 올라감)
    # 커브 본체: 촉머리 직전까지만 그림
    body_end = n_seg  # default: 끝까지
    accum = 0
    for i in range(n_seg - 1, 0, -1):
        seg_dx = pts[i + 1][0] - pts[i][0]
        seg_dy = pts[i + 1][1] - pts[i][1]
        accum += math.sqrt(seg_dx ** 2 + seg_dy ** 2)
        if accum >= head_len:
            body_end = i
            break

    # 커브 본체 그리기 — 교과서 스타일 tapering (시작 가늘게→끝 두껍게)
    # Moloney/Clayden 화살표: 시작점에서 가늘고 촉머리로 갈수록 두꺼워짐
    # body_end + 2 까지 그려서 촉머리와 이음새 갭 방지
    draw_end = min(body_end + 2, n_seg)
    for i in range(draw_end):
        t = i / max(draw_end, 1)  # 0.0 (시작) → 1.0 (끝)
        seg_width = max(2, int(width * (0.4 + 0.6 * t)))  # 40%→100% tapering
        draw.line([(int(pts[i][0]), int(pts[i][1])),
                    (int(pts[i + 1][0]), int(pts[i + 1][1]))],
                   fill=color, width=seg_width)

    # ── 촉머리 (filled arrowhead) ──
    ex, ey = pts[-1]  # 끝점
    # 촉머리 방향 벡터 (커브 끝부분의 접선)
    bx, by = pts[body_end]
    adx, ady = ex - bx, ey - by
    al = math.sqrt(adx ** 2 + ady ** 2) or 1
    adx, ady = adx / al, ady / al

    if half_head:
        # 반쪽 촉머리 (1전자 이동: 라디칼) — fishhook arrow
        # M548: 0.35 → 0.40 (Rule O fishhook >= 0.40; mechanism_visibility_standard.md §3)
        _FISH_W = 0.40  # Magic: 0.40 = 라디칼 fishhook 식별 가능 최소 비율 (Rule O)
        w1x = ex - head_len * adx + head_len * _FISH_W * ady
        w1y = ey - head_len * ady - head_len * _FISH_W * adx
        draw.polygon([(int(ex), int(ey)),
                       (int(w1x), int(w1y)),
                       (int(ex - head_len * 0.4 * adx), int(ey - head_len * 0.4 * ady))],
                      fill=color)
    else:
        # 꽉 찬 삼각형 촉머리 (2전자 이동) — Moloney/Clayden 스타일
        # M548: 0.35 → 0.42 (Rule O half_w >= 0.42; mechanism_visibility_standard.md §3)
        head_w = 0.42  # Magic: 0.42 = 화살촉 너비/길이 비율 (교과서 McMurry 표준, Rule O)
        w1x = ex - head_len * adx + head_len * head_w * ady
        w1y = ey - head_len * ady - head_len * head_w * adx
        w2x = ex - head_len * adx - head_len * head_w * ady
        w2y = ey - head_len * ady + head_len * head_w * adx
        draw.polygon([(int(ex), int(ey)),
                       (int(w1x), int(w1y)),
                       (int(w2x), int(w2y))],
                      fill=color)

    # ── Enhancement: Electron count indicator near arrowhead ──
    # "2e⁻" for double-barb (ionic), "1e⁻" for single-barb (radical/fishhook)
    if show_electron_count:
        e_label = "1e\u207b" if half_head else "2e\u207b"
        try:
            e_font = _get_pil_font(8)
        except Exception as e:
            logger.warning("Font loading failed: %s", e)
            e_font = None
        if e_font:
            # Position: offset from arrowhead tip, perpendicular to arrow direction
            e_off_x = int(-ady * 14)  # 14px perpendicular offset from arrowhead
            e_off_y = int(adx * 14)
            e_px = int(ex) + e_off_x
            e_py = int(ey) + e_off_y
            # Small white background for readability
            try:
                e_bbox = e_font.getbbox(e_label)
                e_tw = e_bbox[2] - e_bbox[0]
                e_th = e_bbox[3] - e_bbox[1]
            except AttributeError as e:
                logger.debug("Attribute not available: %s", e)
                e_tw, e_th = 18, 10  # fallback size estimate
            draw.rectangle([e_px - 1, e_py - 1, e_px + e_tw + 1, e_py + e_th + 1],
                           fill=(255, 255, 255, 220) if hasattr(draw, '_image') else 'white')
            draw.text((e_px, e_py), e_label, fill='#666666', font=e_font)

    # ── Enhancement: Arrow annotation label at curve midpoint ──
    # Small gray text (8pt) above/below the curve apex describing the arrow type
    if arrow_label:
        try:
            lbl_font = _get_pil_font(8)
        except Exception as e:
            logger.warning("Font loading failed: %s", e)
            lbl_font = None
        if lbl_font:
            # Curve midpoint (the control point area = apex of the curve)
            lbl_x = int(cx)
            lbl_y = int(cy)
            try:
                lbl_bbox = lbl_font.getbbox(arrow_label)
                lbl_tw = lbl_bbox[2] - lbl_bbox[0]
                lbl_th = lbl_bbox[3] - lbl_bbox[1]
            except AttributeError as e:
                logger.debug("Attribute not available: %s", e)
                lbl_tw = len(arrow_label) * 5  # rough estimate
                lbl_th = 10
            # Center the label on the curve apex, offset slightly away from curve
            lbl_x -= lbl_tw // 2
            # Place above apex if curve goes up, below if curve goes down
            if direction == 'up':
                lbl_y -= lbl_th + 4  # above the apex
            else:
                lbl_y += 4  # below the apex
            # White background for readability
            draw.rectangle([lbl_x - 2, lbl_y - 1, lbl_x + lbl_tw + 2, lbl_y + lbl_th + 1],
                           fill=(255, 255, 255, 220) if hasattr(draw, '_image') else 'white')
            draw.text((lbl_x, lbl_y), arrow_label, fill='#666666', font=lbl_font)


def _infer_arrow_label(step: dict, arr_def: tuple, is_inner: bool = False) -> str:
    """Infer a descriptive label for a curved arrow from step context.

    Returns short text like "nucleophilic attack", "proton transfer",
    "bond breaking", etc. for display near the arrow curve midpoint.
    """
    if not isinstance(step, dict):
        logger.warning("_infer_arrow_label: step is not dict (type=%s)", type(step).__name__)
        return ''
    label_text = step.get('label', '').lower()
    annot_text = step.get('annotation', '').lower()
    combined = label_text + ' ' + annot_text

    # Check if the arrow_def tuple itself carries a label (4th element for arrow_defs,
    # or 5th for inner_arrows which have half_head at index 3)
    # ★ dict-format arrows (gold standard): extract label from 'label' key
    if isinstance(arr_def, dict):
        return arr_def.get('label', '') or ''
    if not is_inner and isinstance(arr_def, (tuple, list)) and len(arr_def) >= 4 and isinstance(arr_def[3], str):
        return arr_def[3]
    if is_inner and isinstance(arr_def, (tuple, list)) and len(arr_def) >= 5 and isinstance(arr_def[4], str):
        return arr_def[4]

    # Infer from step label/annotation keywords
    if any(kw in combined for kw in ['nucleophil', 'sn2', 'attack']):
        return 'nucleophilic attack'
    elif any(kw in combined for kw in ['proton', 'deproton', 'protona']):
        return 'proton transfer'
    elif any(kw in combined for kw in ['eliminat', 'e1cb', 'e2', 'e1']):
        return 'elimination'
    elif any(kw in combined for kw in ['bond break', 'leaving', 'departure']):
        return 'bond breaking'
    elif any(kw in combined for kw in ['bond form', 'cycliz']):
        return 'bond formation'
    elif any(kw in combined for kw in ['rearrange', 'shift', 'migrat']):
        return 'rearrangement'
    elif any(kw in combined for kw in ['radical', 'homoly']):
        return 'radical'
    elif any(kw in combined for kw in ['oxidat']):
        return 'oxidation'
    elif any(kw in combined for kw in ['reduct']):
        return 'reduction'
    elif any(kw in combined for kw in ['addition', 'electrophil']):
        return 'electrophilic addition'
    elif any(kw in combined for kw in ['substitut']):
        return 'substitution'
    # No match — return empty (no label displayed)
    return ''


def _draw_bond_change_indicator(draw, x: int, y: int, change_type: str,
                                 font) -> None:
    """Draw a bond-breaking or bond-forming indicator near the given position.

    change_type: 'break' (red X), 'form' (green +), 'partial' (orange ~)
    """
    size = 10
    if change_type == 'break':
        # Red X for bond breaking
        draw.line([(x - size, y - size), (x + size, y + size)], fill='#cc0000', width=2)
        draw.line([(x - size, y + size), (x + size, y - size)], fill='#cc0000', width=2)
    elif change_type == 'form':
        # Green + for bond forming
        draw.line([(x - size, y), (x + size, y)], fill='#009900', width=2)
        draw.line([(x, y - size), (x, y + size)], fill='#009900', width=2)
    elif change_type == 'partial':
        # Orange dashed for partial bond (transition state)
        for i in range(0, size * 2, 4):
            draw.line([(x - size + i, y), (x - size + i + 2, y)],
                      fill='#ff6600', width=2)


def _detect_bond_changes(r_mol, p_mol) -> dict:
    """Detect bonds broken and formed between reactant and product.

    Returns dict with 'broken' and 'formed' lists of (atom_idx1, atom_idx2) tuples.
    """
    result = {'broken': [], 'formed': []}
    if r_mol is None or p_mol is None:
        return result
    try:
        r_bonds = set()
        for bond in r_mol.GetBonds():
            r_bonds.add((bond.GetBeginAtomIdx(), bond.GetEndAtomIdx()))
            r_bonds.add((bond.GetEndAtomIdx(), bond.GetBeginAtomIdx()))
        p_bonds = set()
        for bond in p_mol.GetBonds():
            p_bonds.add((bond.GetBeginAtomIdx(), bond.GetEndAtomIdx()))
            p_bonds.add((bond.GetEndAtomIdx(), bond.GetBeginAtomIdx()))
        # Bonds in reactant but not product = broken
        for b in r_bonds:
            if b not in p_bonds and b[0] < b[1]:
                result['broken'].append(b)
        # Bonds in product but not reactant = formed
        for b in p_bonds:
            if b not in r_bonds and b[0] < b[1]:
                result['formed'].append(b)
    except Exception as e:
        logger.warning("_detect_bond_changes failed: %s", e)
    return result


def _get_atom_fragment_map(mol) -> dict:
    """Build a mapping from atom index → fragment index for a molecule.

    Used to detect whether two atoms are in the same or different fragments
    (important for cross-fragment arrow routing in multi-fragment SMILES).

    Returns dict {atom_idx: fragment_idx} or empty dict on failure.
    """
    if mol is None:
        return {}
    try:
        frag_lists = Chem.GetMolFrags(mol)  # tuple of tuples
        result = {}
        for frag_idx, atom_indices in enumerate(frag_lists):
            for aidx in atom_indices:
                result[aidx] = frag_idx
        return result
    except Exception as e:
        logger.warning("_get_atom_fragment_map failed: %s", e)
        return {}


def _get_atom_pixel_coords(mol, drawer, mol_w, mol_h):
    """Map RDKit atom indices to pixel coordinates using the MolDraw2D drawer.

    After DrawMolecule + FinishDrawing, the drawer knows the coordinate transform.
    Returns dict {atom_idx: (px_x, px_y)}.
    """
    coords = {}
    try:
        conf = mol.GetConformer()
    except Exception as e:
        logger.warning("_get_atom_pixel_coords failed: %s", e)
        return coords
    for i in range(mol.GetNumAtoms()):
        try:
            # Use drawer's GetDrawCoords which maps molecule coords → pixel coords
            pt = drawer.GetDrawCoords(i)
            coords[i] = (int(pt.x), int(pt.y))
        except Exception as e:
            logger.warning("_get_atom_pixel_coords failed: %s", e)
            # Fallback: manual affine mapping from 2D coords
            pos = conf.GetAtomPosition(i)
            coords[i] = (int(pos.x), int(pos.y))
    return coords


def _render_mol_clean(smi: str, w: int = 400, h: int = 300) -> Tuple[Optional['PILImage'], dict]:
    """RDKit 분자를 하이라이트 없이 깨끗하게 렌더링 + 원자 픽셀 좌표 반환.

    형식전하(+/-)와 라디칼(·)을 원자 옆에 크고 명확하게 표시.
    결합선과 겹치지 않도록 PIL 오버레이로 강조.

    Multi-fragment SMILES (e.g. "[OH-].CCBr"): 각 fragment를 별도 렌더링 후
    generous spacing으로 수평 배치. "+" 구분자 표시.
    """
    from PIL import Image as PILImage, ImageDraw, ImageFont
    mol = Chem.MolFromSmiles(smi) if smi else None
    if mol is None:
        return PILImage.new('RGB', (w, h), 'white'), {}

    # ── Multi-fragment detection: "." separator in SMILES ──
    # RDKit default 2D layout places fragments too close → inter-fragment
    # arrows become indistinguishable from intra-molecular arrows.
    # Solution: render each fragment separately with generous gaps.
    try:
        frags = Chem.GetMolFrags(mol, asMols=True, sanitizeFrags=True)
    except Exception as e:
        logger.warning("_render_mol_clean failed: %s", e)
        frags = [mol]
    if len(frags) > 1:
        return _render_multi_fragment(smi, mol, frags, w, h)

    AllChem.Compute2DCoords(mol)

    # ── Fallback fragment separation for single-mol path ──
    # If GetMolFrags(asMols=True) failed above but the mol still has multiple
    # disconnected components, spread them apart in 2D coordinate space.
    try:
        _fallback_frags = Chem.GetMolFrags(mol, asMols=False)
        if len(_fallback_frags) > 1:
            conf = mol.GetConformer()
            for fi in range(1, len(_fallback_frags)):
                prev_max_x = max(conf.GetAtomPosition(a).x for a in _fallback_frags[fi - 1])
                curr_min_x = min(conf.GetAtomPosition(a).x for a in _fallback_frags[fi])
                current_gap = curr_min_x - prev_max_x
                desired_gap = 3.0  # Angstroms — much larger than RDKit default (~1.5)
                if current_gap < desired_gap:
                    shift = desired_gap - current_gap
                    for a in _fallback_frags[fi]:
                        pos = conf.GetAtomPosition(a)
                        conf.SetAtomPosition(a, Point3D(pos.x + shift, pos.y, pos.z))
    except Exception as e:
        logger.warning("_render_mol_clean failed: %s", e)

    drawer = Draw.rdMolDraw2D.MolDraw2DCairo(w, h)
    opts = drawer.drawOptions()
    opts.bondLineWidth = 2.5
    opts.padding = 0.15  # 약간 더 여유 (원자 레이블 잘림 방지)
    # ── 원자 레이블-결합 간 여백 확보 ──
    # additionalAtomLabelPadding: 원자 레이블과 결합선 사이 추가 여백 (기본 0.0)
    opts.additionalAtomLabelPadding = 0.12  # 전하 기호가 결합선에 겹치지 않도록
    try:
        opts.atomLabelFontSize = 20  # 더 큰 원자 레이블 (18→20)
    except AttributeError as e:
        logger.debug("Attribute not available: %s", e)
    try:
        opts.annotationFontScale = 1.2
    except AttributeError as e:
        logger.debug("Attribute not available: %s", e)
    # ── 원자 색상 단일화: 모든 헤테로원자 검정으로 통일 ──
    # 기본 RDKit 색상(O=빨강, N=파랑, S=노랑)이 화살표 색상과 충돌 방지
    # 형식전하([+], [-])와 라디칼([·])은 검정 레이블로 명확히 표시됨
    try:
        opts.useBWAtomPalette()  # 모든 원자 기호를 검정으로
    except AttributeError as e:
        logger.debug("Attribute not available: %s", e)
    # ── TASK-MECH-080: 소분자(< 4 heavy atoms) 렌더링 개선 ──
    # 에틸렌(C=C), 오존(O=O=O) 등 원자 수가 적은 분자는 bare line segment로 보임.
    # explicitMethyl=True로 CH3, CH2 등을 명시, 분자식 라벨도 아래에 표시.
    n_heavy = mol.GetNumHeavyAtoms()
    if n_heavy < 4:
        try:
            opts.explicitMethyl = True  # CH3, CH2, NH2 등 명시 표시
        except AttributeError as e:
            logger.debug("Attribute not available: %s", e)
        # 추가: 모든 원자에 대해 explicit H를 표시하여 가독성 확보
        try:
            mol = Chem.AddHs(mol)
            AllChem.Compute2DCoords(mol)
        except Exception as e:
            logger.warning("2D coordinate computation failed: %s", e)
    drawer.DrawMolecule(mol)  # 하이라이트 없이 깨끗하게
    drawer.FinishDrawing()
    atom_px = _get_atom_pixel_coords(mol, drawer, w, h)
    png_data = drawer.GetDrawingText()
    img = PILImage.open(io.BytesIO(png_data))

    # ── 라디칼(·) 오버레이만 적용 (PIL) ──
    # RDKit이 이미 형식전하(+/-)를 superscript로 정확히 표시하므로
    # PIL로 추가 오버레이하면 이중 렌더링 → "O1" 같은 아티팩트 발생.
    # 라디칼 점(·)만 별도 오버레이 (RDKit이 라디칼을 명확히 표시 안 함).
    img = _overlay_radical_dots_only(img, mol, atom_px, w, h)

    # ── 비공유전자쌍 자동 렌더링 (교과서: :O: :N: 스타일) ──
    # O, N, S 등 비공유전자쌍 보유 원자에 두 점(:) 표시
    img = _overlay_lone_pairs(img, mol, atom_px, w, h)

    return img, atom_px


def _render_multi_fragment(original_smi: str, combined_mol, frag_mols: list,
                           w: int, h: int) -> Tuple[Optional['PILImage'], dict]:
    """Render multi-fragment SMILES with generous horizontal spacing.

    Each fragment is rendered independently via MolDraw2DCairo, then composited
    side-by-side with "+" symbols between them. Atom pixel coordinates are mapped
    back to the original combined molecule's atom indices so that arrow routing
    works correctly.

    Returns (PIL image, {original_atom_idx: (px_x, px_y)}).
    """
    from PIL import Image as PILImage, ImageDraw, ImageFont
    import io as _io

    n_frags = len(frag_mols)
    gap = 60  # px between fragments (generous spacing for clear visual separation)
    plus_zone = 24  # px for "+" symbol within the gap

    # ── Map fragment atom indices → original mol atom indices ──
    # Chem.GetMolFrags returns atom index lists per fragment
    try:
        frag_atom_lists = Chem.GetMolFrags(combined_mol)  # tuple of tuples of atom indices
    except Exception as e:
        logger.warning("_render_multi_fragment failed: %s", e)
        frag_atom_lists = None

    # ── Allocate width proportional to atom count ──
    total_atoms = sum(m.GetNumAtoms() for m in frag_mols)
    if total_atoms == 0:
        return PILImage.new('RGB', (w, h), 'white'), {}
    available_w = w - (n_frags - 1) * gap
    min_frag_w = 80  # minimum width per fragment

    frag_widths = []
    for fm in frag_mols:
        n_atoms = fm.GetNumAtoms()
        fw = max(min_frag_w, int(available_w * n_atoms / total_atoms))
        frag_widths.append(fw)

    # Normalize widths to fit within available_w
    total_fw = sum(frag_widths)
    if total_fw > available_w:
        scale = available_w / total_fw
        frag_widths = [max(min_frag_w, int(fw * scale)) for fw in frag_widths]

    # ── Render each fragment independently ──
    frag_images = []  # (PIL image, width)
    frag_atom_px_local = []  # dict {local_atom_idx: (px, py)}

    for fi, frag_mol in enumerate(frag_mols):
        fw = frag_widths[fi]
        fh = h
        try:
            AllChem.Compute2DCoords(frag_mol)
            drawer = Draw.rdMolDraw2D.MolDraw2DCairo(fw, fh)
            opts = drawer.drawOptions()
            opts.bondLineWidth = 2.5
            opts.padding = 0.15
            opts.additionalAtomLabelPadding = 0.12
            try:
                opts.atomLabelFontSize = 20
            except AttributeError as e:
                logger.debug("Attribute not available: %s", e)
            try:
                opts.annotationFontScale = 1.2
            except AttributeError as e:
                logger.debug("Attribute not available: %s", e)
            try:
                opts.useBWAtomPalette()
            except AttributeError as e:
                logger.debug("Attribute not available: %s", e)
            # Small molecules: show explicit H
            n_heavy = frag_mol.GetNumHeavyAtoms()
            if n_heavy < 4:
                try:
                    opts.explicitMethyl = True
                except AttributeError as e:
                    logger.debug("Attribute not available: %s", e)
                try:
                    frag_mol = Chem.AddHs(frag_mol)
                    AllChem.Compute2DCoords(frag_mol)
                except Exception as e:
                    logger.warning("2D coordinate computation failed: %s", e)
            drawer.DrawMolecule(frag_mol)
            drawer.FinishDrawing()
            local_px = _get_atom_pixel_coords(frag_mol, drawer, fw, fh)
            png_data = drawer.GetDrawingText()
            frag_img = PILImage.open(_io.BytesIO(png_data))
        except Exception as e:
            logger.warning("Fragment processing failed: %s", e)
            frag_img = PILImage.new('RGB', (fw, fh), 'white')
            local_px = {}

        # Apply radical dots and lone pairs overlays
        try:
            frag_img = _overlay_radical_dots_only(frag_img, frag_mol, local_px, fw, fh)
            frag_img = _overlay_lone_pairs(frag_img, frag_mol, local_px, fw, fh)
        except Exception as e:
            logger.warning("Fragment processing failed: %s", e)

        frag_images.append(frag_img)
        frag_atom_px_local.append(local_px)

    # ── Composite onto canvas ──
    canvas = PILImage.new('RGB', (w, h), 'white')
    draw = ImageDraw.Draw(canvas)

    all_atom_px = {}  # {original_atom_idx: (px_x, px_y)} relative to canvas
    x_offset = 0

    for fi in range(n_frags):
        frag_img = frag_images[fi]
        fw = frag_widths[fi]

        # Paste fragment image
        canvas.paste(frag_img, (x_offset, 0))

        # Map local fragment atom coords → original mol atom indices
        local_px = frag_atom_px_local[fi]
        if frag_atom_lists is not None and fi < len(frag_atom_lists):
            orig_indices = frag_atom_lists[fi]
            for local_idx, (px, py) in local_px.items():
                if local_idx < len(orig_indices):
                    orig_idx = orig_indices[local_idx]
                    all_atom_px[orig_idx] = (px + x_offset, py)
        else:
            # Fallback: use local indices directly (imperfect but safe)
            for local_idx, (px, py) in local_px.items():
                all_atom_px[local_idx] = (px + x_offset, py)

        # Draw "+" between fragments (standard chemistry notation)
        if fi < n_frags - 1:
            plus_x = x_offset + fw + gap // 2
            try:
                plus_font = _get_pil_font(16, bold=True)
            except Exception as e:
                logger.warning("Font loading failed: %s", e)
                plus_font = None
            draw.text((plus_x - 6, h // 2 - 10), "+",
                      fill='#888888', font=plus_font)

        x_offset += fw + gap

    return canvas, all_atom_px


def _overlay_charge_radical_symbols(img, mol, atom_px: dict,
                                     w: int, h: int):
    """형식전하(+/-)와 라디칼(·)을 원자 옆에 까만 텍스트로 오버레이.

    기존 그리기 레이어/이론적 구조 레이어와 동일한 스타일:
    - 원이나 색상 장식 없음
    - 까만 +/- 텍스트를 약간 크게, 원자 레이블 우상단에 배치
    - 라디칼은 까만 점(·) — 작은 채움 원
    """
    from PIL import Image as PILImage, ImageDraw, ImageFont

    charged_atoms = []  # (idx, charge, radical_electrons)
    for atom in mol.GetAtoms():
        fc = atom.GetFormalCharge()
        nr = atom.GetNumRadicalElectrons()
        if fc != 0 or nr > 0:
            idx = atom.GetIdx()
            if idx in atom_px:
                charged_atoms.append((idx, fc, nr))

    if not charged_atoms:
        return img  # 전하/라디칼 없으면 그대로 반환

    img = img.convert('RGBA')
    overlay = img.copy()
    draw = ImageDraw.Draw(overlay)

    # 폰트 크기: 원자 레이블보다 약간 크게 (7.5% of smaller dim)
    font_size = max(16, min(30, int(min(w, h) * 0.075)))
    try:
        font = ImageFont.truetype("arialbd.ttf", font_size)  # Bold for visibility
    except (OSError, IOError) as e:
        logger.debug("Font file not found: %s", e)
        try:
            font = ImageFont.truetype("arial.ttf", font_size)
        except (OSError, IOError) as e:
            logger.debug("Font file not found: %s", e)
            try:
                font = ImageFont.truetype("DejaVuSans-Bold.ttf", font_size)
            except (OSError, IOError) as e:
                logger.debug("Font file not found: %s", e)
                font = ImageFont.load_default()

    # 라디칼 점 반지름
    radical_dot_r = max(3, int(font_size * 0.25))

    for idx, fc, nr in charged_atoms:
        cx, cy = atom_px[idx]

        # 오프셋: 원자 우상단 (결합선 회피) — 5%/6%로 확대하여 겹침 방지
        off_x = int(min(w, h) * 0.05)   # 5% rightward
        off_y = int(min(w, h) * 0.06)   # 6% upward

        # 결합이 우상단 방향이면 전하를 좌상단으로 이동 (겹침 방지)
        atom_obj = mol.GetAtomWithIdx(idx)
        for nb in atom_obj.GetNeighbors():
            nb_idx = nb.GetIdx()
            if nb_idx in atom_px:
                nx, ny = atom_px[nb_idx]
                # 이웃이 우상단에 있는지 (dx > 0, dy < 0 = 위쪽)
                if nx > cx and ny < cy:
                    off_x = -off_x  # 좌측으로 이동
                    break

        if fc != 0:
            charge_text = "+" if fc > 0 else "\u2212"  # U+2212 proper minus sign
            sx = cx + off_x
            sy = cy - off_y

            # 경계 보정
            sx = max(2, min(w - font_size - 2, sx))
            sy = max(2, min(h - font_size - 2, sy))

            # 텍스트 크기 측정
            try:
                bbox = font.getbbox(charge_text)
                tw = bbox[2] - bbox[0]
                th = bbox[3] - bbox[1]
            except AttributeError as e:
                logger.debug("Attribute not available: %s", e)
                tw, th = font_size, font_size

            # 작은 흰색 사각형으로 결합선만 가림 (장식 아님, 가독성용)
            pad = 3  # 패딩 확대 (px) — 결합선 겹침 방지
            draw.rectangle(
                [sx - pad, sy - pad, sx + tw + pad, sy + th + pad],
                fill=(255, 255, 255, 240)
            )

            # 까만 텍스트 — 원, 테두리, 색상 없음
            draw.text((sx, sy), charge_text, fill=(0, 0, 0, 255), font=font)

        if nr > 0:
            # 라디칼: 까만 점 — 전하 옆 또는 원자 우상단
            if fc != 0:
                dot_x = cx + off_x + int(font_size * 1.1)
            else:
                dot_x = cx + off_x
            dot_y = cy - off_y + int(font_size * 0.3)

            # 경계 보정
            dot_x = max(radical_dot_r + 1, min(w - radical_dot_r - 1, dot_x))
            dot_y = max(radical_dot_r + 1, min(h - radical_dot_r - 1, dot_y))

            # 흰색 배경 (결합선 가독성)
            bg_r = radical_dot_r + 2
            draw.ellipse(
                [dot_x - bg_r, dot_y - bg_r, dot_x + bg_r, dot_y + bg_r],
                fill=(255, 255, 255, 240)
            )
            # 까만 점
            draw.ellipse(
                [dot_x - radical_dot_r, dot_y - radical_dot_r,
                 dot_x + radical_dot_r, dot_y + radical_dot_r],
                fill=(0, 0, 0, 255)
            )

    # RGBA → RGB 변환 (PDF 호환)
    result = PILImage.new('RGB', overlay.size, (255, 255, 255))
    result.paste(overlay, mask=overlay.split()[3])
    return result


def _overlay_radical_dots_only(img, mol, atom_px: dict, w: int, h: int):
    """라디칼(·)만 원자 옆에 까만 점으로 오버레이.

    형식전하(+/-)는 RDKit이 이미 정확히 렌더링하므로 여기서는 생략.
    이중 렌더링 시 "O1" 같은 아티팩트가 발생하므로 라디칼 점만 처리.
    """
    from PIL import Image as PILImage, ImageDraw

    radical_atoms = []
    for atom in mol.GetAtoms():
        nr = atom.GetNumRadicalElectrons()
        if nr > 0:
            idx = atom.GetIdx()
            if idx in atom_px:
                radical_atoms.append((idx, nr))

    if not radical_atoms:
        return img  # 라디칼 없으면 그대로 반환

    img = img.convert('RGBA')
    overlay = img.copy()
    draw = ImageDraw.Draw(overlay)

    font_size = max(16, min(30, int(min(w, h) * 0.075)))
    radical_dot_r = max(3, int(font_size * 0.25))

    for idx, nr in radical_atoms:
        cx, cy = atom_px[idx]

        off_x = int(min(w, h) * 0.05)
        off_y = int(min(w, h) * 0.06)

        # 결합이 우상단 방향이면 전하를 좌상단으로 이동
        atom_obj = mol.GetAtomWithIdx(idx)
        for nb in atom_obj.GetNeighbors():
            nb_idx = nb.GetIdx()
            if nb_idx in atom_px:
                nx, ny = atom_px[nb_idx]
                if nx > cx and ny < cy:
                    off_x = -off_x
                    break

        dot_x = cx + off_x
        dot_y = cy - off_y + int(font_size * 0.3)

        dot_x = max(radical_dot_r + 1, min(w - radical_dot_r - 1, dot_x))
        dot_y = max(radical_dot_r + 1, min(h - radical_dot_r - 1, dot_y))

        # 흰색 배경 (결합선 가독성)
        bg_r = radical_dot_r + 2
        draw.ellipse(
            [dot_x - bg_r, dot_y - bg_r, dot_x + bg_r, dot_y + bg_r],
            fill=(255, 255, 255, 240)
        )
        # 까만 점
        draw.ellipse(
            [dot_x - radical_dot_r, dot_y - radical_dot_r,
             dot_x + radical_dot_r, dot_y + radical_dot_r],
            fill=(0, 0, 0, 255)
        )

    result = PILImage.new('RGB', overlay.size, (255, 255, 255))
    result.paste(overlay, mask=overlay.split()[3])
    return result


def _overlay_lone_pairs(img, mol, atom_px: dict, w: int, h: int):
    """비공유전자쌍을 O, N, S 등 헤테로원자에 두 점(:)으로 표시.

    교과서 스타일: 원자 기호 양옆 또는 위아래에 두 점을 그려
    비공유전자쌍의 존재를 명시. 전자 이동 화살표의 출발점이 됨.
    """
    from PIL import Image as PILImage, ImageDraw
    import math

    # 비공유전자쌍 보유 원자 찾기
    lp_atoms = []  # (idx, n_lone_pairs, symbol)
    for atom in mol.GetAtoms():
        sym = atom.GetSymbol()
        idx = atom.GetIdx()
        if idx not in atom_px:
            continue
        # 비공유전자쌍 수 계산 (원자가 전자 - 결합 전자 - 형식전하)
        n_lp = 0
        if sym == 'O':
            n_lp = 2  # 산소: 보통 2쌍
            if atom.GetFormalCharge() == -1:
                n_lp = 3  # O⁻: 3쌍
        elif sym == 'N':
            n_lp = 1  # 질소: 보통 1쌍
            if atom.GetFormalCharge() == -1:
                n_lp = 2  # N⁻: 2쌍
            elif atom.GetDegree() >= 4:
                n_lp = 0  # NH4+: 0쌍
        elif sym == 'S':
            n_lp = 2  # 황: 보통 2쌍
        elif sym in ('F', 'Cl', 'Br', 'I'):
            n_lp = 3  # 할로겐: 3쌍
        if n_lp > 0:
            lp_atoms.append((idx, n_lp, sym))

    if not lp_atoms:
        return img

    img = img.convert('RGBA')
    overlay = img.copy()
    draw = ImageDraw.Draw(overlay)

    # ★ 이론적 구조 렌더러(layer_logic.py)와 동일한 스타일:
    #   점 크기 3.0px, 점 간격 8px (perp 4.0 × 2), 원자 거리 22px
    dot_r = max(3, int(min(w, h) * 0.012))  # 점 반지름: 3~4px (v8.4 기준 3.0)
    dot_gap = max(8, int(min(w, h) * 0.025))  # 두 점 사이 간격: 8px (perp 4.0 × 2)
    offset = max(20, int(min(w, h) * 0.06))  # 원자에서 거리: 20~22px (겹침 방지)

    for idx, n_lp, sym in lp_atoms:
        cx, cy = atom_px[idx]

        # 결합 방향 분석: 원자 주변 결합이 어디로 나가는지 확인
        # 비공유전자쌍은 결합이 없는 방향에 그림
        bond_angles = []
        for nbr in mol.GetAtomWithIdx(idx).GetNeighbors():
            ni = nbr.GetIdx()
            if ni in atom_px:
                dx = atom_px[ni][0] - cx
                dy = atom_px[ni][1] - cy
                bond_angles.append(math.atan2(dy, dx))

        # 결합이 없는 방향 찾기 (최대 빈 공간)
        if bond_angles:
            bond_angles.sort()
            best_angle = 0
            max_gap = 0
            for i in range(len(bond_angles)):
                next_i = (i + 1) % len(bond_angles)
                gap = bond_angles[next_i] - bond_angles[i]
                if next_i == 0:
                    gap += 2 * math.pi
                if gap > max_gap:
                    max_gap = gap
                    best_angle = bond_angles[i] + gap / 2
        else:
            best_angle = -math.pi / 2  # 위쪽 기본값

        # 최대 2쌍까지 그림 (가독성)
        pairs_to_draw = min(n_lp, 2)
        for p in range(pairs_to_draw):
            if pairs_to_draw == 1:
                angle = best_angle
            else:
                # 두 방향으로 분산 (90도 간격)
                angle = best_angle + (p - 0.5) * math.pi * 0.5

            lp_x = cx + offset * math.cos(angle)
            lp_y = cy + offset * math.sin(angle)

            # 두 점 그리기 (비공유전자쌍 = 2전자 = 2점)
            # 결합 방향에 수직인 방향으로 두 점 배치
            perp_angle = angle + math.pi / 2
            d1x = lp_x + dot_gap * 0.5 * math.cos(perp_angle)
            d1y = lp_y + dot_gap * 0.5 * math.sin(perp_angle)
            d2x = lp_x - dot_gap * 0.5 * math.cos(perp_angle)
            d2y = lp_y - dot_gap * 0.5 * math.sin(perp_angle)

            # 점 경계 보정
            d1x = max(dot_r, min(w - dot_r, d1x))
            d1y = max(dot_r, min(h - dot_r, d1y))
            d2x = max(dot_r, min(w - dot_r, d2x))
            d2y = max(dot_r, min(h - dot_r, d2y))

            # 까만 점 그리기
            draw.ellipse([d1x - dot_r, d1y - dot_r, d1x + dot_r, d1y + dot_r],
                         fill=(0, 0, 0, 200))
            draw.ellipse([d2x - dot_r, d2y - dot_r, d2x + dot_r, d2y + dot_r],
                         fill=(0, 0, 0, 200))

    # RGBA → RGB
    result = PILImage.new('RGB', overlay.size, (255, 255, 255))
    result.paste(overlay, mask=overlay.split()[3])
    return result


def _ai_generate_mechanism_intermediates(reactant_smi: str, product_smi: str,
                                           conditions: str = "") -> Optional[list]:
    """AI(Groq/Gemini) 기반 반응 메커니즘 중간체 자동 생성.

    어떤 반응이든 처리 가능 — 하드코딩 없음.
    Returns list of dicts or None on failure.
    """
    try:
        from lead_optimizer import call_llm
    except ImportError as e:
        logger.debug("lead_optimizer.call_llm not available: %s", e)
        return None

    # 반응물/생성물 구조 차이 분석 (AI에게 힌트 제공)
    r_mol_tmp = Chem.MolFromSmiles(reactant_smi) if reactant_smi else None
    if r_mol_tmp is None and reactant_smi:
        logger.warning("Invalid SMILES for DryLab AI hint reactant: %s", reactant_smi)
    p_mol_tmp = Chem.MolFromSmiles(product_smi) if product_smi else None
    if p_mol_tmp is None and product_smi:
        logger.warning("Invalid SMILES for DryLab AI hint product: %s", product_smi)
    struct_hint = ""
    if r_mol_tmp and p_mol_tmp:
        r_syms = sorted([a.GetSymbol() for a in r_mol_tmp.GetAtoms()])
        p_syms = sorted([a.GetSymbol() for a in p_mol_tmp.GetAtoms()])
        added = []
        removed = []
        r_copy = list(r_syms)
        for s in p_syms:
            if s in r_copy:
                r_copy.remove(s)
            else:
                added.append(s)
        p_copy = list(p_syms)
        for s in r_syms:
            if s in p_copy:
                p_copy.remove(s)
            else:
                removed.append(s)
        if added or removed:
            struct_hint = f"\nAtoms added in product: {added}. Atoms removed: {removed}."

    prompt = f"""Generate a DETAILED step-by-step reaction mechanism as JSON.

Reactant: {reactant_smi}
Product: {product_smi}
Conditions: {conditions}{struct_hint}

CORE PRINCIPLE: Someone looking ONLY at the diagram should understand exactly which bond breaks, which bond forms, and what intermediate structure exists at each step.

INSTRUCTIONS:
1. Identify the EXACT reaction type.
2. Generate 3-6 steps. Each step = ONE elementary bond change.
3. "smiles" = the main substrate/intermediate at that step. MUST show:
   - Formal charges ([S+], [O-], [N+]) where applicable
   - Radical electrons as atom mapping or explicit radical
   - The EXACT intermediate structure, not just reactant repeated
4. "reagent_smiles" = the attacking species. Use "" if none.
5. "annotation" = MUST clearly state:
   - Which specific bond breaks (e.g., "N-Br bond homolysis")
   - Which specific bond forms (e.g., "C-Br bond forms")
   - What intermediate is generated (e.g., "arenium ion intermediate")
6. LAST step smiles = product: {product_smi}

INTERMEDIATE DETAIL REQUIREMENTS:
- After nucleophilic attack: show tetrahedral intermediate with charges
- After electrophilic attack: show carbocation/arenium ion explicitly
- After radical abstraction: show radical center on specific carbon
- After bond heterolysis: show both charged fragments
- Transition states: describe in annotation, not as SMILES

COMMON REACTIONS:
- NBS bromination: NBS=O=C1CCC(=O)N1Br, Br radical=[Br], succinimide=O=C1CCC(=O)[NH]1
- mCPBA: OOC(=O)c1cccc(Cl)c1, mCBA=[O-]C(=O)c1cccc(Cl)c1
- Friedel-Crafts: AlCl3=Cl[Al](Cl)Cl, show arenium ion with [CH+] or [cH+]
- SN2: show backside attack, inversion, leaving group departure
- Epoxidation: concerted [2+1] with mCPBA butterfly mechanism
- TsCl: TsCl=ClS(=O)(=O)c1ccc(C)cc1

SMILES RULES (CRITICAL):
- ALL SMILES MUST be valid RDKit-parseable. Test mentally before outputting.
- Radicals: [CH2] (not [CH]), [Br] (Br radical)
- Charges: [S+], [O-], [N+], [CH+]
- DO NOT write [CH3CH2...] - use proper SMILES: CC
- DO NOT use dots (.) in single molecule SMILES unless it's a salt/complex
- Simple molecules: ethanol=CCO, benzene=c1ccccc1, ethylbenzene=CCc1ccccc1
- Tosyl chloride=ClS(=O)(=O)c1ccc(C)cc1
- AlCl3=Cl[Al](Cl)Cl
- Arenium ion from benzene + Et+: CC[C+]1C=CC=CC1 (cyclohexadienyl cation)
- DO NOT use "empty", "none", "null" as SMILES

Return ONLY a JSON array:
[{{"smiles":"...","reagent_smiles":"...","mechanism_type":"radical or ionic","annotation":"BOND CHANGE: X-Y breaks, A-B forms. Intermediate: ...","byproduct":"","step_label":"Step N: Short Title","arrow_hint":"fishhook or full"}}]"""

    system = ("You are a PhD organic chemistry professor. Return ONLY valid JSON. "
              "No markdown. Focus on showing EXACT intermediate structures with "
              "correct charges and radical centers. Every SMILES must be RDKit-valid.")

    response = call_llm(prompt, system)
    if not response:
        return None

    # Parse JSON from response
    import json as _json
    text = response.strip()
    # Strip markdown code fences if present
    if text.startswith('```'):
        text = text.split('\n', 1)[1] if '\n' in text else text[3:]
    if text.endswith('```'):
        text = text[:-3].strip()
    # Sometimes AI wraps in ```json ... ```
    if text.startswith('json'):
        text = text[4:].strip()

    try:
        ai_steps = _json.loads(text)
    except _json.JSONDecodeError:
        logger.debug("AI mechanism JSON parse failed: %s", text[:200])
        return None

    if not isinstance(ai_steps, list) or len(ai_steps) < 2:
        return None

    # Validate SMILES with RDKit
    _EMPTY_WORDS = {'empty', 'none', 'null', 'n/a', '-', '""', "''"}
    validated = []
    for st in ai_steps:
        if not isinstance(st, dict):
            logger.warning("AI mechanism step is not dict (type=%s), skipping", type(st).__name__)
            continue
        smi = st.get('smiles', '')
        if isinstance(smi, str) and smi.lower().strip() in _EMPTY_WORDS:
            smi = ''
        mol = Chem.MolFromSmiles(smi) if smi else None
        if mol is None and smi:
            logger.debug("AI returned invalid SMILES: %s", smi)
            continue  # Skip invalid entries
        reagent = st.get('reagent_smiles', '')
        if isinstance(reagent, str) and reagent.lower().strip() in _EMPTY_WORDS:
            reagent = ''
        byp = st.get('byproduct', '')
        if isinstance(byp, str) and byp.lower().strip() in _EMPTY_WORDS:
            byp = ''
        if reagent:
            rmol = Chem.MolFromSmiles(reagent)
            if rmol is None:
                reagent = ''  # Drop invalid reagent SMILES
        validated.append({
            'smiles': smi,
            'reagent_smiles': reagent,
            'mechanism_type': st.get('mechanism_type', 'ionic'),
            'annotation': st.get('annotation', ''),
            'byproduct': byp,
            'step_label': st.get('step_label', ''),
            'arrow_hint': st.get('arrow_hint', 'full'),
        })

    return validated if len(validated) >= 2 else None


def _auto_detect_arrows_between(smi_current: str, smi_next: str,
                                  mech_type: str = "ionic") -> list:
    """연속 중간체 간 결합 변화 감지 → 화살표 정의 자동 생성.

    MCS (Maximum Common Substructure) 기반 원자 매핑을 사용하여
    원자 수가 다른 경우(반응물→중간체에서 원자 추가/제거)도 처리 가능.

    Returns list of (from_ref, to_ref, direction, is_half_head).
    ★ 결합 끊김: from_ref = 'bond:i:j' (결합 중점에서 시작), to_ref = 전기음성도 높은 원자
    ★ 결합 형성: from_ref = 친핵 원자 idx, to_ref = 친전자 원자 idx
    화살표는 current mol의 원자 인덱스 기준.
    """
    mol1 = Chem.MolFromSmiles(smi_current) if smi_current else None
    mol2 = Chem.MolFromSmiles(smi_next) if smi_next else None
    if mol1 is None or mol2 is None:
        return []

    arrows = []
    is_radical = (mech_type == 'radical')

    # ── 1차: BondChangeDetector MCS 기반 탐지 (원자 수 달라도 작동) ──
    if _BOND_DETECTOR_AVAILABLE:
        try:
            detector = BondChangeDetector()
            result = detector.detect(smi_current, smi_next)
            if result and result.bond_changes:
                for bc in result.bond_changes:
                    ai = bc.atom_i
                    aj = bc.atom_j

                    # 이탈기/유입 원자 (-1) → current mol에 좌표 없으므로 skip
                    if aj == -1:
                        continue
                    # 인덱스가 current mol 범위 밖이면 skip
                    if ai >= mol1.GetNumAtoms() or aj >= mol1.GetNumAtoms():
                        continue

                    sym_i = mol1.GetAtomWithIdx(ai).GetSymbol()
                    sym_j = mol1.GetAtomWithIdx(aj).GetSymbol()
                    en_i = _ELEM_ELECTRONEG.get(sym_i, 2.5)  # Pauling 전기음성도
                    en_j = _ELEM_ELECTRONEG.get(sym_j, 2.5)

                    if bc.is_broken or bc.change_type == 'order_decrease':
                        # ★ 결합 끊김: 결합 중점에서 전기음성도 높은 원자로 화살표
                        # 'bond:i:j' 형식 → 렌더러가 두 원자의 중점 좌표 계산
                        bond_ref = f'bond:{ai}:{aj}'
                        target = ai if en_i >= en_j else aj
                        arrows.append((bond_ref, target, 'up', is_radical))

                    elif bc.is_formed or bc.change_type == 'order_increase':
                        # 결합 형성 → 친핵체(전기음성도 높은)에서 친전자체로
                        if en_i >= en_j:
                            arrows.append((ai, aj, 'down', is_radical))
                        else:
                            arrows.append((aj, ai, 'down', is_radical))

                if arrows:
                    # ★ 강화된 중복 제거: 양방향 + 동일 원자쌍 체크
                    seen = set()
                    unique_arrows = []
                    for arr in arrows:
                        # key: 정렬된 원자쌍 (방향 무관)
                        a0, a1 = str(arr[0]), str(arr[1])
                        key = tuple(sorted([a0, a1]))
                        if key not in seen:
                            seen.add(key)
                            unique_arrows.append(arr)
                    return unique_arrows[:6]  # max 6 arrows (교과서급: 단계당 3-4개)
        except Exception as e:
            logger.warning(f"BondChangeDetector 화살표 감지 실패, 폴백 사용: {e}")
            arrows = []

    # ── 2차 폴백: 원자 수 동일 시 직접 비교 (기존 로직) ──
    if mol1.GetNumAtoms() == mol2.GetNumAtoms():
        bonds1 = {}
        for b in mol1.GetBonds():
            key = (b.GetBeginAtomIdx(), b.GetEndAtomIdx())
            bonds1[key] = b.GetBondTypeAsDouble()
            bonds1[(key[1], key[0])] = b.GetBondTypeAsDouble()

        bonds2 = {}
        for b in mol2.GetBonds():
            key = (b.GetBeginAtomIdx(), b.GetEndAtomIdx())
            bonds2[key] = b.GetBondTypeAsDouble()
            bonds2[(key[1], key[0])] = b.GetBondTypeAsDouble()

        # 끊어진 결합: mol1에 있지만 mol2에 없음 → 결합 중점에서 화살표
        for (i, j), order in bonds1.items():
            if i < j and (i, j) not in bonds2:
                sym_i = mol1.GetAtomWithIdx(i).GetSymbol()
                sym_j = mol1.GetAtomWithIdx(j).GetSymbol()
                en_i = _ELEM_ELECTRONEG.get(sym_i, 2.5)
                en_j = _ELEM_ELECTRONEG.get(sym_j, 2.5)
                # ★ 결합 중점에서 전기음성도 높은 원자로 화살표
                bond_ref = f'bond:{i}:{j}'
                target = i if en_i >= en_j else j
                arrows.append((bond_ref, target, 'up', is_radical))

        # 형성된 결합: mol2에 있지만 mol1에 없음 → 친핵 공격 화살표
        for (i, j), order in bonds2.items():
            if i < j and (i, j) not in bonds1:
                sym_i = mol1.GetAtomWithIdx(i).GetSymbol() if i < mol1.GetNumAtoms() else 'C'
                sym_j = mol1.GetAtomWithIdx(j).GetSymbol() if j < mol1.GetNumAtoms() else 'C'
                en_i = _ELEM_ELECTRONEG.get(sym_i, 2.5)
                en_j = _ELEM_ELECTRONEG.get(sym_j, 2.5)
                if en_i >= en_j:
                    arrows.append((i, j, 'down', is_radical))
                else:
                    arrows.append((j, i, 'down', is_radical))

    # 결합차수 변화 화살표 추가: C=O → C-O 등
    if mol1.GetNumAtoms() == mol2.GetNumAtoms():
        for (i, j), order1 in bonds1.items():
            if i < j and (i, j) in bonds2:
                order2 = bonds2[(i, j)]
                if order1 != order2:  # 결합차수 변화 (예: 이중→단일)
                    sym_i = mol1.GetAtomWithIdx(i).GetSymbol()
                    sym_j = mol1.GetAtomWithIdx(j).GetSymbol()
                    en_i = _ELEM_ELECTRONEG.get(sym_i, 2.5)
                    en_j = _ELEM_ELECTRONEG.get(sym_j, 2.5)
                    if order1 > order2:  # 이중→단일: π전자가 결합 중점에서 전기음성도 높은 쪽으로
                        bond_ref = f'bond:{i}:{j}'
                        target = i if en_i >= en_j else j
                        arrows.append((bond_ref, target, 'up', is_radical))

    # ★ 최종 중복 제거 (양방향 + bond ref 통합)
    seen = set()
    unique = []
    for arr in arrows:
        a0, a1 = str(arr[0]), str(arr[1])
        key = tuple(sorted([a0, a1]))
        if key not in seen:
            seen.add(key)
            unique.append(arr)
    return unique[:6]  # max 6 arrows (교과서급: 단계당 3-4개 전자 이동)


# Pauling 전기음성도 (화살표 방향 결정용)
_ELEM_ELECTRONEG = {
    'H': 2.20, 'C': 2.55, 'N': 3.04, 'O': 3.44, 'F': 3.98,
    'P': 2.19, 'S': 2.58, 'Cl': 3.16, 'Br': 2.96, 'I': 2.66,
    'Li': 0.98, 'Na': 0.93, 'Mg': 1.31, 'Al': 1.61, 'B': 2.04,
}


def _make_step(mol_smi: str, label: str, reagent_smi: str = '',
               annotation: str = '', condition: str = '',
               half_arrows: bool = False, byproduct_smi: str = '',
               side_text: str = '', arrow_defs: list = None,
               inner_arrows: list = None,
               reagent_inner: list = None,
               mech_badge: str = '',
               is_intermediate: bool = False,
               is_transition_state: bool = False) -> dict:
    """메커니즘 단계 dict 생성 헬퍼 (모듈 레벨).

    mech_badge: 'EAS', 'SN2', 'Radical', 'Concerted' 등 메커니즘 유형 배지.
    is_intermediate: True → 대괄호 [ ] 로 감싸 불안정 중간체임을 표시.
    is_transition_state: True → 대괄호 + ‡ 기호로 전이상태 표시.
    """
    return {
        'mol_smi': mol_smi,
        'label': label,
        'reagent_smi': reagent_smi,
        'arrow_defs': arrow_defs or [],
        'inner_arrows': inner_arrows or [],
        'reagent_inner': reagent_inner or [],
        'annotation': annotation,
        'condition': condition,
        'half_arrows': half_arrows,
        'byproduct_smi': byproduct_smi,
        'side_text': side_text,
        'mech_badge': mech_badge,
        'is_intermediate': is_intermediate,
        'is_transition_state': is_transition_state,
    }


# ── RDKit 기반 중간체 SMILES 생성 헬퍼 (str.replace 대체) ──


def _rdkit_replace_carbonyl_with(smi: str, new_group: str) -> Optional[str]:
    """SMARTS 반응으로 C=O 카르보닐을 새 그룹으로 치환.

    Args:
        smi: 반응물 SMILES
        new_group: 치환 SMARTS 생성물측 (예: '(=NNC)' → hydrazone, '(=NO)' → oxime)
    Returns:
        유효한 중간체 SMILES 또는 None
    """
    mol = Chem.MolFromSmiles(smi)
    if mol is None:
        logger.warning("SMILES 파싱 실패: %s", smi)
        return None
    try:
        rxn_smarts = f'[C:1](=[O:2])>>[C:1]{new_group}'
        rxn = AllChem.ReactionFromSmarts(rxn_smarts)
        if rxn is None:
            logger.warning("ReactionFromSmarts 파싱 실패")
            return None
        products = rxn.RunReactants((mol,))
        if products and len(products) > 0:
            p = products[0][0]
            try:
                Chem.SanitizeMol(p)
                result_smi = Chem.MolToSmiles(p)
                _val = Chem.MolFromSmiles(result_smi)
                if _val is not None:  # Rule L: None guard
                    return result_smi
            except Exception as e:
                logger.warning("_rdkit_replace_carbonyl_with failed: %s", e)
    except Exception as e:
        logger.warning("_rdkit_replace_carbonyl_with failed: %s", e)
    return None


def _rdkit_protonate_carbonyl(smi: str) -> Optional[str]:
    """RWMol로 첫 번째 C=O의 산소를 양성자화 → C=[OH+].

    Returns: 유효한 SMILES 또는 None
    """
    mol = Chem.MolFromSmiles(smi)
    if mol is None:
        logger.warning("SMILES 파싱 실패: %s", smi)
        return None
    rw = Chem.RWMol(mol)
    for bond in rw.GetBonds():
        if bond.GetBondTypeAsDouble() == 2.0:
            a1, a2 = bond.GetBeginAtom(), bond.GetEndAtom()
            c_atom, o_atom = None, None
            if a1.GetSymbol() == 'C' and a2.GetSymbol() == 'O':
                c_atom, o_atom = a1, a2
            elif a2.GetSymbol() == 'C' and a1.GetSymbol() == 'O':
                c_atom, o_atom = a2, a1
            if c_atom is not None and o_atom is not None:
                o_atom.SetFormalCharge(1)
                o_atom.SetNumExplicitHs(o_atom.GetNumExplicitHs() + 1)
                try:
                    Chem.SanitizeMol(rw)
                    result = Chem.MolToSmiles(rw)
                    _val = Chem.MolFromSmiles(result)
                    if _val is not None:  # Rule L: None guard
                        return result
                except Exception as e:
                    logger.warning("_rdkit_protonate_carbonyl failed: %s", e)
                break
    return None


def _rdkit_make_tetrahedral_ester_int(smi: str, alcohol_smi: str = 'CCO') -> Optional[str]:
    """Fischer 에스터화 사면체 중간체: RCOOH + R'OH → RC(OH)(OH)(OR').

    Returns: 유효한 SMILES 또는 None
    """
    mol = Chem.MolFromSmiles(smi)
    alc = Chem.MolFromSmiles(alcohol_smi)
    if mol is None or alc is None:
        return None
    try:
        rxn = AllChem.ReactionFromSmarts(
            '[C:1](=[O:2])[OH:3].[OH:4][C:5]>>[C:1]([OH:2])([OH:3])([O:4][C:5])'
        )
        if rxn is None:
            logger.warning("ReactionFromSmarts 파싱 실패")
            return None
        products = rxn.RunReactants((mol, alc))
        if products and len(products) > 0:
            p = products[0][0]
            try:
                Chem.SanitizeMol(p)
                result = Chem.MolToSmiles(p)
                _val = Chem.MolFromSmiles(result)
                if _val is not None:  # Rule L: None guard
                    return result
            except Exception as e:
                logger.warning("_rdkit_make_tetrahedral_ester_int failed: %s", e)
    except Exception as e:
        logger.warning("_rdkit_make_tetrahedral_ester_int failed: %s", e)
    return None


def _rdkit_replace_halide_with_azide(smi: str) -> Optional[str]:
    """RDKit SMARTS로 할로겐을 아지드로 치환: R-X → R-N=[N+]=[N-].

    Returns: 유효한 SMILES 또는 None
    """
    mol = Chem.MolFromSmiles(smi)
    if mol is None:
        logger.warning("SMILES 파싱 실패: %s", smi)
        return None
    try:
        rxn = AllChem.ReactionFromSmarts(
            '[C:1][Cl,Br,I:2]>>[C:1]N=[N+]=[N-]'
        )
        if rxn is None:
            logger.warning("ReactionFromSmarts 파싱 실패")
            return None
        products = rxn.RunReactants((mol,))
        if products and len(products) > 0:
            p = products[0][0]
            try:
                Chem.SanitizeMol(p)
                result = Chem.MolToSmiles(p)
                _val = Chem.MolFromSmiles(result)
                if _val is not None:  # Rule L: None guard
                    return result
            except Exception as e:
                logger.warning("_rdkit_replace_halide_with_azide failed: %s", e)
    except Exception as e:
        logger.warning("_rdkit_replace_halide_with_azide failed: %s", e)
    return None


def _rdkit_make_diazonium(smi: str) -> Optional[str]:
    """RDKit SMARTS로 방향족 아민 → 디아조늄: ArNH2 → Ar[N+]#N.

    Returns: 유효한 SMILES 또는 None
    """
    mol = Chem.MolFromSmiles(smi)
