        rxn = AllChem.ReactionFromSmarts('[c:1][NH2:2]>>[c:1][N+:2]#N')
        if rxn is None:
            logger.warning("ReactionFromSmarts 파싱 실패")
            return None
        products = rxn.RunReactants((mol,))
        if products and len(products) > 0:
            p = products[0][0]
