                mol_smi=reactant_smi,
                label='(i) Knoevenagel Condensation (Ketone + Cyanoacetate)',
                reagent_smi='N#CCC(=O)OCC',
                annotation='Et₃N deprotonates α-CH₂ of ethyl cyanoacetate (pKa ~13). '
