    # ★ Cycle 18: Kumada, Tebbe, Petasis, Buchwald-Hartwig, Chan-Lam
    ('kumada',           'kumada_coupling'),
    ('kumada coupling',  'kumada_coupling'),
    ('rmgbr coupling',   'kumada_coupling'),
    ('grignard coupling','kumada_coupling'),
    ('tebbe',            'tebbe_olefination'),
    ('tebbe olefination','tebbe_olefination'),
    ('cp2tich2',         'tebbe_olefination'),
    ('petasis reagent',  'tebbe_olefination'),
    # ★ Petasis reaction MUST come AFTER Tebbe 'petasis reagent' (Tebbe's Cp2Ti=CH2 = Petasis reagent)
    ('petasis borono',   'petasis_reaction'),
    ('petasis reaction', 'petasis_reaction'),
    ('borono-mannich',   'petasis_reaction'),
    ('petasis',          'petasis_reaction'),
    # ★ Buchwald-Hartwig MUST come BEFORE generic 'amination' if ever added
    ('buchwald-hartwig', 'buchwald_hartwig'),
    ('buchwald hartwig', 'buchwald_hartwig'),
    ('buchwald',         'buchwald_hartwig'),
    ('hartwig',          'buchwald_hartwig'),
    ('pd amination',     'buchwald_hartwig'),
    # ★ Chan-Lam: Cu-mediated C-N coupling
    ('chan-lam',         'chan_lam_coupling'),
    ('chan lam',         'chan_lam_coupling'),
    ('cu(oac)2 coupling','chan_lam_coupling'),
    ('copper amination', 'chan_lam_coupling'),
    # ★ Cycle 20: L4 exam named reactions (2026-03-22)
    ('acyloin',          'acyloin_condensation'),
