    ('thorpe',           'thorpe_ziegler'),
    ('darzens',          'darzens_condensation'),
    ('knoevenagel',      'knoevenagel_condensation'),
    ('baylis-hillman',   'baylis_hillman'),
    ('baylis',           'baylis_hillman'),
    ('hillman',          'baylis_hillman'),
    ('staudinger ligation', 'staudinger_ligation'),
    ('staudinger',       'staudinger_ligation'),
    ('kulinkovich',      'kulinkovich_reaction'),
    ('trost allylation', 'trost_allylation'),
    ('trost',            'trost_allylation'),
    ('mukaiyama aldol',  'mukaiyama_aldol'),
    ('mukaiyama',        'mukaiyama_aldol'),
    # Reagent-based detection
    ('ozonolysis',       'ozonolysis'),
    # NOTE: 'o3' removed — false positive: 'k2co3' contains 'o3' substring.
    # Ozonolysis from 'o3' is handled via the guard block in _match_conditions_to_mech_key.
    ('radical',          'radical_halogenation'),
    ('nbs',              'radical_halogenation'),
    # EAS variants
    ('nitration',        'eas_nitration'),
    ('hno3',             'eas_nitration'),
    ('sulfonation',      'eas_sulfonation'),
    ('so3',              'eas_sulfonation'),
    ('friedel',          'friedel_crafts_alkylation'),
    ('tosyl',            'tosylation'),
    ('tscl',             'tosylation'),
    # Composite conditions
    ('amidation',        'amidation'),
    ('amide',            'amidation'),
    # ★ Structural keyword triggers for 4 newly hardcoded templates (Curtius/BV/Wittig/Claisen)
    # Note: 'curtius' and 'baeyer' are guarded in _match_conditions_to_mech_key → return None
    # so they never reach this table.  The entries below handle phosphorus ylide synonyms for
    # Wittig (wittig itself is mapped above at line ~13549) and 'claisen' alone → rearrangement.
    ('ph3p',             'wittig'),         # Ph3P reagent → Wittig reaction
    ('pph3',             'wittig'),         # PPh3 phosphine → Wittig
    ('ylide',            'wittig'),         # ylide → Wittig (guard: not sulfonium)
    ('phosphorane',      'wittig'),         # phosphorane → Wittig
    ('phosphonium',      'wittig'),         # phosphonium salt → Wittig
    ('claisen',          'claisen_rearrangement'),  # guard in _match_conditions_to_mech_key
    # ★ Cycle 19: 4 newly hardcoded templates (Pinacol/Cope/Hofmann-Elim/Appel)
    # These keywords map to existing gold mechanism keys (hardcoded templates take priority
    # via _generate_generic_mechanism structural detection; gold-standard used as fallback)
    ('pinacol rearrangement', 'pinacol'),          # pinacol_rearrangement → gold key 'pinacol'
    ('1,2-diol',             'pinacol'),            # vicinal diol + acid context
    ('pinacolone',           'pinacol'),            # product name → pinacol rearrangement
    ('cope rearrangement',   'cope_rearrangement'), # explicit name (also at line ~13825)
    ('[3,3]-sigmatropic',    'cope_rearrangement'), # IUPAC sigmatropic descriptor
    ('1,5-diene',            'cope_rearrangement'), # substrate class descriptor
    ('hofmann elimination',  'hofmann'),            # hofmann_elimination → gold key 'hofmann'
    ('anti-zaitsev',         'hofmann'),            # regioselectivity keyword
    ('exhaustive methylation','hofmann'),           # reagent protocol keyword
    ('quaternary ammonium',  'hofmann'),            # substrate class
    ('appel reaction',       'appel'),              # appel_reaction → gold key 'appel'
    ('pph3 ccl4',            'appel'),              # reagent pair → Appel
    ('ph3p ccl4',            'appel'),              # reagent pair variant
    ('cbr4',                 'appel'),              # CBr4 variant of Appel
    # ★ Cycle 20: 3 newly hardcoded templates (Williamson/Wolff-Kishner/Mitsunobu)
    # Guards in _match_conditions_to_mech_key return None → hardcoded template takes priority
    ('williamson ether',     'williamson'),         # explicit named-reaction string
    ('wolff-kishner',        'wolff_kishner'),      # hyphenated form
    ('wolff kishner',        'wolff_kishner'),      # spaced form
    ('huang-minlon',         'wolff_kishner'),      # Huang-Minlon modification keyword
    ('huang minlon',         'wolff_kishner'),      # spaced form
